import React, { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import {
  ReactFlow,
  ReactFlowProvider,
  Background,
  BackgroundVariant,
  Controls,
  MiniMap,
  addEdge,
  applyNodeChanges,
  applyEdgeChanges,
} from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import {
  Save,
  FolderOpen,
  FilePlus,
  Trash2,
  Settings,
  RefreshCw,
  X,
  PanelLeftOpen,
  PanelLeftClose,
  Download,
  Upload,
} from 'lucide-react';
import apiService from '../services/apiService';
import { StateMachineNode } from '../components/statemachine/StateMachineNode';
import { NodePalette } from '../components/statemachine/NodePalette';
import { ConfigPanel } from '../components/statemachine/ConfigPanel';
import { NODE_DEFINITIONS, createNodeData, buildLuaOutputs } from '../components/statemachine/nodeDefinitions';

const nodeTypes = { smnode: StateMachineNode };

let nodeIdCounter = 0;

// ── Convert React Flow graph → YAML-like data model for backend ──

function isEventType(type) {
  return type?.startsWith('event-');
}

function isStateType(type) {
  return type === 'predefined' || type === 'lua-script' || type === 'final-state'
    || type === 'switch' || type === 'if-else' || type === 'loop' || type === 'delay';
}

function graphToStateMachineData(nodes, edges) {
  const stateNodes = nodes.filter((n) => isStateType(n.data.type));
  const eventNodes = nodes.filter((n) => isEventType(n.data.type));

  let initial = null;
  const states = {};
  const events = {};

  // Build events map
  for (const en of eventNodes) {
    const cfg = en.data.config || {};
    const eventName = cfg.eventName || en.data.type;
    const outEdges = edges.filter((e) => e.source === en.id);
    for (const oe of outEdges) {
      const target = nodes.find((n) => n.id === oe.target);
      if (target) {
        const targetName = target.data.config?.stateName || target.id;
        const eventEntry = { target: targetName };
        if (en.data.type === 'event-property-change') {
          eventEntry.propertyName = cfg.propertyName || '';
          eventEntry.propertyComparator = cfg.propertyComparator || '==';
          eventEntry.propertyValue = cfg.propertyValue || '';
        }
        events[eventName] = eventEntry;
        if (eventName === 'Start') {
          initial = targetName;
        }
      }
    }
  }

  for (const sn of stateNodes) {
    const cfg = sn.data.config || {};
    const name = cfg.stateName || sn.id;

    const action = {};
    if (sn.data.type === 'predefined' || sn.data.type === 'final-state') {
      action.type = 'predefined';
      action.name = cfg.actionName || '';
    } else if (sn.data.type === 'lua-script') {
      action.type = 'lua';
    } else if (sn.data.type === 'switch') {
      action.type = 'switch';
      action.property = cfg.property || '';
      action.rules = cfg.rules || [];
    } else if (sn.data.type === 'if-else') {
      action.type = 'if-else';
      action.field = cfg.field || '';
      action.operator = cfg.operator || '==';
      action.value = cfg.value || '';
    } else if (sn.data.type === 'loop') {
      action.type = 'loop';
      action.field = cfg.field || '';
      action.count = cfg.count || '';
    } else if (sn.data.type === 'delay') {
      action.type = 'delay';
      action.delay = cfg.delay || 1000;
      action.unit = cfg.unit || 'ms';
    }

    if (Array.isArray(cfg.actionParams) && cfg.actionParams.length > 0) {
      action.params = cfg.actionParams.map((p) => ({
        name: p.name || '',
        type: p.type,
        value:
          sn.data.type === 'predefined' && (p.value === '' || p.value === null || p.value === undefined)
            ? (p.defaultValue ?? '')
            : p.value,
      }));
    }
    if (sn.data.type === 'lua-script' && cfg.luaScript) {
      action.script = cfg.luaScript;
    }

    const nextMap = {};
    const outEdgesFromState = edges.filter((e) => e.source === sn.id);
    for (const edge of outEdgesFromState) {
      const targetNode = nodes.find((n) => n.id === edge.target);
      if (!targetNode) continue;

      const destName = targetNode.data.config?.stateName || targetNode.id;
      // Extract return code from the sourceHandle (e.g. "out-0" → "0")
      const code = edge.sourceHandle?.replace('out-', '') || '0';
      nextMap[code] = destName === 'finish' ? null : destName;
    }

    states[name] = { action, next: nextMap };
  }

  return { initial, states, events };
}

// ── Convert backend data model → React Flow graph ──

function stateMachineDataToGraph(data) {
  const nodes = [];
  const edges = [];
  let x = 100;
  const y = 200;
  const xStep = 300;
  const stateIdMap = {};

  if (!data || !data.states) return { nodes: [], edges: [] };

  const stateNames = Object.keys(data.states);

  for (const name of stateNames) {
    const stateData = data.states[name];
    const actionType = stateData.action?.type || 'predefined';
    const isFinish =
      stateData.action?.name === 'Finish' ||
      actionType === 'finish';

    let nodeType;
    if (isFinish) {
      nodeType = 'final-state';
    } else if (actionType === 'lua') {
      nodeType = 'lua-script';
    } else if (['switch', 'if-else', 'loop', 'delay'].includes(actionType)) {
      nodeType = actionType;
    } else {
      nodeType = 'predefined';
    }

    const def = NODE_DEFINITIONS.find((d) => d.type === nodeType);
    if (!def) continue;

    const nodeData = createNodeData(def);
    nodeData.config.stateName = name;

    if (stateData.action) {
      nodeData.config.actionName = stateData.action.name || '';
      nodeData.config.actionParams = Array.isArray(stateData.action.params)
        ? stateData.action.params.map((p) => ({
          name: p.name || '',
          type: p.type,
          value: String(p.value),
          defaultValue: p.defaultValue ?? '',
        }))
        : [];
      if (stateData.action.script) {
        nodeData.config.luaScript = stateData.action.script;
      }
      if (actionType === 'switch') {
        nodeData.config.property = stateData.action.property || '';
        nodeData.config.rules = stateData.action.rules || [];
      } else if (actionType === 'if-else') {
        nodeData.config.field = stateData.action.field || '';
        nodeData.config.operator = stateData.action.operator || '==';
        nodeData.config.value = stateData.action.value || '';
      } else if (actionType === 'loop') {
        nodeData.config.field = stateData.action.field || '';
        nodeData.config.count = stateData.action.count || '';
      } else if (actionType === 'delay') {
        nodeData.config.delay = stateData.action.delay || 1000;
        nodeData.config.unit = stateData.action.unit || 'ms';
      }
    }

    // For lua-script nodes, build outputs from the next map keys
    if (nodeType === 'lua-script' && stateData.next) {
      const codes = Object.keys(stateData.next);
      if (codes.length > 0) {
        nodeData.config.outputCodes = codes;
        nodeData.outputs = buildLuaOutputs(codes);
      }
    }

    nodeIdCounter++;
    const id = `node_${Date.now()}_${nodeIdCounter}`;
    stateIdMap[name] = id;
    nodes.push({
      id,
      type: 'smnode',
      position: { x, y },
      data: nodeData,
    });
    x += xStep;
  }

  // State-to-state transitions
  for (const name of stateNames) {
    const stateData = data.states[name];
    const sourceId = stateIdMap[name];
    if (!sourceId || !stateData.next) continue;

    for (const [code, targetName] of Object.entries(stateData.next)) {
      const resolvedTarget = targetName || 'finish';
      const targetId = stateIdMap[resolvedTarget];
      if (!targetId) continue;

      edges.push({
        id: `edge_${sourceId}_${targetId}_${code}`,
        source: sourceId,
        target: targetId,
        sourceHandle: `out-${code}`,
        targetHandle: 'in',
        animated: true,
        label: code,
      });
    }
  }

  // Reconstruct event nodes
  if (data.events) {
    const EVENT_TYPE_MAP = {
      Start: 'event-start',
      Disconnect: 'event-disconnect',
      Death: 'event-death',
      PropertyChange: 'event-property-change',
    };
    let evX = 100;

    for (const [eventName, eventValue] of Object.entries(data.events)) {
      const eventType = EVENT_TYPE_MAP[eventName];
      if (!eventType) continue;

      const def = NODE_DEFINITIONS.find((d) => d.type === eventType);
      if (!def) continue;

      nodeIdCounter++;
      const eventId = `node_${Date.now()}_${nodeIdCounter}`;
      const eventData = createNodeData(def);

      // eventValue can be a string (legacy) or an object { target, propertyName, propertyValue }
      let targetStateName;
      if (typeof eventValue === 'string') {
        targetStateName = eventValue;
      } else if (eventValue && typeof eventValue === 'object') {
        targetStateName = eventValue.target;
        if (eventType === 'event-property-change') {
          eventData.config.propertyName = eventValue.propertyName || '';
          eventData.config.propertyComparator = eventValue.propertyComparator || '==';
          eventData.config.propertyValue = eventValue.propertyValue || '';
        }
      }

      nodes.push({
        id: eventId,
        type: 'smnode',
        position: { x: evX, y: y - 150 },
        data: eventData,
      });
      evX += 250;

      const targetId = targetStateName ? stateIdMap[targetStateName] : null;
      if (targetId) {
        edges.push({
          id: `edge_${eventId}_${targetId}`,
          source: eventId,
          target: targetId,
          sourceHandle: 'out',
          targetHandle: 'in',
          animated: true,
        });
      }
    }
  }

  return { nodes, edges };
}

// ── Inner editor component (needs ReactFlow context) ──

function StateMachineEditor() {
  const [nodes, setNodes] = useState([]);
  const [edges, setEdges] = useState([]);
  const [machines, setMachines] = useState([]);
  const [selectedMachine, setSelectedMachine] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [dirty, setDirty] = useState(false);
  const [saving, setSaving] = useState(false);
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [configNodeId, setConfigNodeId] = useState(null);
  const [toast, setToast] = useState(null);
  const [actionDefinitions, setActionDefinitions] = useState([]);
  const [showActionManager, setShowActionManager] = useState(false);
  const [actionManagerLoading, setActionManagerLoading] = useState(false);
  const [selectedActionName, setSelectedActionName] = useState('');
  const [actionForm, setActionForm] = useState({
    name: '',
    description: '',
    paramsText: '[]',
    outputsText: '[]',
  });
  const reactFlowRef = useRef(null);

  const showToast = useCallback((msg, type = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 2500);
  }, []);

  const normalizeActions = useCallback((rows) => (
    rows.map((a) => ({
      name: a.name,
      description: a.description || '',
      params: (() => { try { return JSON.parse(a.params || '[]'); } catch { return []; } })(),
      outputs: (() => { try { return JSON.parse(a.outputs || '[]'); } catch { return []; } })(),
    }))
  ), []);

  // ── Load machine list + action definitions ──
  useEffect(() => {
    setIsLoading(true);
    Promise.all([
      apiService.getAllStateMachines(),
      apiService.getAllMachineActions().catch(() => ({ data: [] })),
    ])
      .then(([machinesRes, actionsRes]) => {
        setMachines(Array.isArray(machinesRes?.data) ? machinesRes.data : []);
        const rawActions = Array.isArray(actionsRes?.data) ? actionsRes.data : [];
        setActionDefinitions(normalizeActions(rawActions));
      })
      .catch(() => showToast('Failed to load data', 'error'))
      .finally(() => setIsLoading(false));
  }, [showToast, normalizeActions]);

  // ── Refresh action definitions ──
  const refreshActions = useCallback(() => {
    apiService.getAllMachineActions().catch(() => ({ data: [] }))
      .then((res) => {
        const rawActions = Array.isArray(res?.data) ? res.data : [];
        setActionDefinitions(normalizeActions(rawActions));
        showToast('Actions refreshed');
      });
  }, [showToast, normalizeActions]);

  const resetActionForm = useCallback(() => {
    setSelectedActionName('');
    setActionForm({
      name: '',
      description: '',
      paramsText: '[]',
      outputsText: '[]',
    });
  }, []);

  const copyNewActionForm = useCallback(() => {
    const baseName = actionForm.name?.trim() || selectedActionName || 'NewAction';
    const copiedName = `${baseName}_copy`;
    setSelectedActionName('');
    setActionForm((prev) => ({
      ...prev,
      name: copiedName,
    }));
  }, [actionForm.name, selectedActionName]);

  const openActionManager = useCallback(() => {
    setShowActionManager(true);
    resetActionForm();
    refreshActions();
  }, [refreshActions, resetActionForm]);

  const loadActionToForm = useCallback(async (name) => {
    try {
      setActionManagerLoading(true);
      const res = await apiService.getMachineAction(name);
      const row = Array.isArray(res?.data) ? res.data[0] : null;
      if (!row) return;
      setSelectedActionName(row.name);
      setActionForm({
        name: row.name || '',
        description: row.description || '',
        paramsText: JSON.stringify((() => { try { return JSON.parse(row.params || '[]'); } catch { return []; } })(), null, 2),
        outputsText: JSON.stringify((() => { try { return JSON.parse(row.outputs || '[]'); } catch { return []; } })(), null, 2),
      });
    } catch {
      showToast('Failed to load action', 'error');
    } finally {
      setActionManagerLoading(false);
    }
  }, [showToast]);

  const saveActionFromForm = useCallback(async () => {
    const name = actionForm.name.trim();
    if (!name) {
      showToast('Action name is required', 'error');
      return;
    }

    let parsedParams;
    let parsedOutputs;
    try {
      parsedParams = JSON.parse(actionForm.paramsText || '[]');
      parsedOutputs = JSON.parse(actionForm.outputsText || '[]');
      if (!Array.isArray(parsedParams) || !Array.isArray(parsedOutputs)) {
        throw new Error('params/outputs must be arrays');
      }
    } catch {
      showToast('Params/Outputs must be valid JSON arrays', 'error');
      return;
    }

    try {
      setActionManagerLoading(true);
      const paramsJson = JSON.stringify(parsedParams);
      const outputsJson = JSON.stringify(parsedOutputs);
      const desc = actionForm.description || '';
      const existing = actionDefinitions.find((a) => a.name === name);
      if (existing) {
        await apiService.updateMachineAction(name, paramsJson, outputsJson, desc);
        showToast('Action updated');
      } else {
        await apiService.insertMachineAction(name, paramsJson, outputsJson, desc);
        showToast('Action created');
      }
      await refreshActions();
      setSelectedActionName(name);
    } catch {
      showToast('Failed to save action', 'error');
    } finally {
      setActionManagerLoading(false);
    }
  }, [actionForm, actionDefinitions, refreshActions, showToast]);

  const deleteActionFromForm = useCallback(async () => {
    const name = actionForm.name.trim();
    if (!name) return;
    if (!window.confirm(`Delete action "${name}"?`)) return;
    try {
      setActionManagerLoading(true);
      await apiService.deleteMachineAction(name);
      showToast('Action deleted');
      await refreshActions();
      resetActionForm();
    } catch {
      showToast('Failed to delete action', 'error');
    } finally {
      setActionManagerLoading(false);
    }
  }, [actionForm.name, refreshActions, resetActionForm, showToast]);

  // ── React Flow change handlers ──
  const onNodesChange = useCallback((changes) => {
    setNodes((nds) => applyNodeChanges(changes, nds));
    setDirty(true);
  }, []);

  const onEdgesChange = useCallback((changes) => {
    setEdges((eds) => applyEdgeChanges(changes, eds));
    setDirty(true);
  }, []);

  const onConnect = useCallback((connection) => {
    setEdges((eds) => addEdge({ ...connection, animated: true }, eds));
    setDirty(true);
  }, []);

  const onInit = useCallback((instance) => {
    reactFlowRef.current = instance;
  }, []);

  // ── Add node ──
  const addNode = useCallback((type, data, position) => {
    nodeIdCounter++;
    const id = `node_${Date.now()}_${nodeIdCounter}`;
    const newNode = { id, type: 'smnode', position, data };
    setNodes((nds) => [...nds, newNode]);
    setDirty(true);
  }, []);

  // ── Update node data ──
  const updateNodeData = useCallback((id, partialData) => {
    setNodes((nds) =>
      nds.map((node) =>
        node.id === id ? { ...node, data: { ...node.data, ...partialData } } : node
      )
    );
    setDirty(true);
  }, []);

  // ── DnD from palette ──
  const onDragOver = useCallback((e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (e) => {
      e.preventDefault();
      const nodeType = e.dataTransfer.getData('application/sm-node');
      if (!nodeType || !reactFlowRef.current) return;

      const def = NODE_DEFINITIONS.find((d) => d.type === nodeType);
      if (!def) return;

      const position = reactFlowRef.current.screenToFlowPosition({
        x: e.clientX,
        y: e.clientY,
      });

      addNode(def.type, createNodeData(def), position);
    },
    [addNode]
  );

  // Click on palette node (mobile-friendly fallback)
  const handleSelectNodeFromPalette = useCallback(
    (nodeType) => {
      const def = NODE_DEFINITIONS.find((d) => d.type === nodeType);
      if (!def || !reactFlowRef.current) return;

      const center = reactFlowRef.current.screenToFlowPosition({
        x: window.innerWidth / 2,
        y: window.innerHeight / 2,
      });
      addNode(def.type, createNodeData(def), center);
    },
    [addNode]
  );

  // ── Double-click node → open config ──
  const onNodeDoubleClick = useCallback((_, node) => {
    setConfigNodeId(node.id);
  }, []);

  // ── Load a machine (always re-fetch from backend) ──
  const handleLoad = useCallback(async () => {
    if (!selectedMachine) return;
    try {
      setIsLoading(true);
      const res = await apiService.getStateMachineByName(selectedMachine);
      const row = Array.isArray(res?.data) ? res.data[0] : res?.data;
      const machine = row && row.name ? row : null;
      if (!machine) {
        showToast('Machine not found on backend', 'error');
        return;
      }

      let data;
      if (machine.value) {
        const parsed = JSON.parse(machine.value);
        if (parsed.nodes && parsed.edges) {
          setNodes(parsed.nodes);
          setEdges(parsed.edges || []);
          setDirty(false);
          showToast('Machine loaded');
          return;
        }
        if (parsed.stateMachine) {
          data = parsed.stateMachine;
        } else if (parsed.initial && parsed.states) {
          data = parsed;
        }
      }

      if (data) {
        const { nodes: n, edges: e } = stateMachineDataToGraph(data);
        setNodes(n);
        setEdges(e);
        setDirty(false);
        showToast('Machine loaded');
      } else {
        showToast('Unknown data format', 'error');
      }
    } catch {
      showToast('Failed to load machine from backend', 'error');
    } finally {
      setIsLoading(false);
    }
  }, [selectedMachine, showToast]);

  // ── Build save payload ──
  const buildPayload = useCallback(() => {
    const stateMachine = graphToStateMachineData(nodes, edges);
    return JSON.stringify({
      stateMachine,
      nodes,
      edges,
      viewport: reactFlowRef.current?.getViewport() || { x: 0, y: 0, zoom: 1 },
    });
  }, [nodes, edges]);

  // Same JSON content as Export button output; stored in pw_machine.json
  const buildExportJson = useCallback(() => {
    const smData = graphToStateMachineData(nodes, edges);
    return JSON.stringify(smData, null, 2);
  }, [nodes, edges]);

  // ── Update existing machine ──
  const handleUpdate = useCallback(async () => {
    if (!selectedMachine) return;
    setSaving(true);
    try {
      await apiService.updateStateMachine(buildPayload(), buildExportJson(), selectedMachine);
      setDirty(false);
      showToast('Machine updated');
    } catch (err) {
      showToast('Failed to update', 'error');
    } finally {
      setSaving(false);
    }
  }, [selectedMachine, buildPayload, buildExportJson, showToast]);

  // ── Save as new ──
  const handleSaveNew = useCallback(async () => {
    const name = prompt('Enter a name for the new machine:');
    if (!name?.trim()) return;
    setSaving(true);
    try {
      await apiService.insertStateMachine(name.trim(), buildPayload(), buildExportJson());
      const res = await apiService.getAllStateMachines();
      const list = Array.isArray(res?.data) ? res.data : [];
      setMachines(list);
      setSelectedMachine(name.trim());
      setDirty(false);
      showToast('Machine saved');
    } catch (err) {
      showToast('Failed to save', 'error');
    } finally {
      setSaving(false);
    }
  }, [buildPayload, buildExportJson, showToast]);

  // ── Delete ──
  const handleDelete = useCallback(async () => {
    if (!selectedMachine) return;
    if (!window.confirm(`Delete "${selectedMachine}"?`)) return;
    try {
      await apiService.deleteStateMachine(selectedMachine);
      const res = await apiService.getAllStateMachines();
      const list = Array.isArray(res?.data) ? res.data : [];
      setMachines(list);
      setSelectedMachine('');
      setNodes([]);
      setEdges([]);
      setDirty(false);
      showToast('Machine deleted');
    } catch (err) {
      showToast('Failed to delete', 'error');
    }
  }, [selectedMachine, showToast]);

  // ── Export YAML-like JSON ──
  const handleExport = useCallback(() => {
    const blob = new Blob([buildExportJson()], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${selectedMachine || 'statemachine'}.json`;
    a.click();
    URL.revokeObjectURL(url);
  }, [buildExportJson, selectedMachine]);

  // ── Import JSON ──
  const handleImport = useCallback(() => {
    const input = document.createElement('input');
    input.type = 'file';
    input.accept = '.json';
    input.onchange = (e) => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = (ev) => {
        try {
          const data = JSON.parse(ev.target.result);
          if (data.nodes && data.edges) {
            setNodes(data.nodes);
            setEdges(data.edges);
          } else if (data.initial && data.states) {
            const { nodes: n, edges: ed } = stateMachineDataToGraph(data);
            setNodes(n);
            setEdges(ed);
          } else if (data.stateMachine) {
            const { nodes: n, edges: ed } = stateMachineDataToGraph(data.stateMachine);
            setNodes(n);
            setEdges(ed);
          }
          setDirty(true);
          showToast('Imported successfully');
        } catch {
          showToast('Invalid file', 'error');
        }
      };
      reader.readAsText(file);
    };
    input.click();
  }, [showToast]);

  // ── Ctrl+S ──
  useEffect(() => {
    const handler = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 's') {
        e.preventDefault();
        if (dirty && selectedMachine) handleUpdate();
      }
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [dirty, selectedMachine, handleUpdate]);

  // ── Edge styling ──
  const styledEdges = useMemo(
    () =>
      edges.map((edge) => ({
        ...edge,
        type: edge.type || 'smoothstep',
        style: { stroke: '#475569', strokeWidth: 2, ...(edge.style || {}) },
      })),
    [edges]
  );

  // ── Config panel data ──
  const configNode = configNodeId ? nodes.find((n) => n.id === configNodeId) : null;

  const defaultEdgeOptions = useMemo(
    () => ({
      type: 'smoothstep',
      animated: true,
      style: { stroke: '#475569', strokeWidth: 2 },
    }),
    []
  );

  return (
    <div className="h-screen flex flex-col overflow-hidden" style={{ backgroundColor: '#0f172a' }}>
      {/* ── Toolbar ── */}
      <div className="h-12 bg-slate-900 border-b border-slate-700 flex items-center px-3 gap-2 shrink-0">
        {/* Sidebar toggle */}
        <button
          onClick={() => setSidebarOpen((v) => !v)}
          className="p-1.5 rounded hover:bg-slate-700 text-slate-400 hover:text-slate-200 transition-colors"
          title={sidebarOpen ? 'Hide palette' : 'Show palette'}
        >
          {sidebarOpen ? <PanelLeftClose size={16} /> : <PanelLeftOpen size={16} />}
        </button>

        <div className="w-px h-6 bg-slate-700" />

        {/* Machine selector */}
        <select
          value={selectedMachine}
          onChange={(e) => setSelectedMachine(e.target.value)}
          className="bg-slate-800 border border-slate-700 rounded-md px-2 py-1 text-xs text-slate-200
            focus:outline-none focus:border-blue-500 max-w-[200px]"
        >
          <option value="">-- Select machine --</option>
          {machines.map((m) => (
            <option key={m.name} value={m.name}>{m.name}</option>
          ))}
        </select>

        <button
          onClick={handleLoad}
          disabled={!selectedMachine || isLoading}
          className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
            bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:opacity-40
            disabled:cursor-not-allowed transition-colors"
          title="Load"
        >
          <FolderOpen size={14} /> Load
        </button>

        <button
          onClick={handleUpdate}
          disabled={!selectedMachine || !dirty || saving}
          className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
            bg-blue-600 hover:bg-blue-500 text-white disabled:opacity-40
            disabled:cursor-not-allowed transition-colors"
          title="Save"
        >
          <Save size={14} /> {saving ? 'Saving...' : 'Save'}
        </button>

        <button
          onClick={handleSaveNew}
          disabled={saving}
          className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
            bg-slate-700 hover:bg-slate-600 text-slate-200 disabled:opacity-40
            disabled:cursor-not-allowed transition-colors"
          title="Save as new"
        >
          <FilePlus size={14} /> New
        </button>

        <button
          onClick={openActionManager}
          className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
            bg-slate-700 hover:bg-slate-600 text-slate-200 transition-colors"
          title="Manage predefined actions"
        >
          <Settings size={14} /> Action Manager
        </button>

        <button
          onClick={handleDelete}
          disabled={!selectedMachine}
          className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
            bg-red-600/20 hover:bg-red-600/40 text-red-400 disabled:opacity-40
            disabled:cursor-not-allowed transition-colors"
          title="Delete"
        >
          <Trash2 size={14} />
        </button>

        <div className="flex-1" />

        {/* Dirty indicator */}
        {dirty && (
          <span className="text-[10px] text-amber-400 font-mono mr-2">unsaved</span>
        )}

        <button
          onClick={handleImport}
          className="p-1.5 rounded hover:bg-slate-700 text-slate-400 hover:text-slate-200 transition-colors"
          title="Import JSON"
        >
          <Upload size={16} />
        </button>

        <button
          onClick={handleExport}
          disabled={nodes.length === 0}
          className="p-1.5 rounded hover:bg-slate-700 text-slate-400 hover:text-slate-200
            disabled:opacity-40 transition-colors"
          title="Export JSON"
        >
          <Download size={16} />
        </button>
      </div>

      {/* ── Main layout ── */}
      <div className="flex flex-1 overflow-hidden relative min-h-0">
        {/* Sidebar */}
        {sidebarOpen && (
          <NodePalette onSelectNode={handleSelectNodeFromPalette} />
        )}

        {/* Canvas */}
        <div className="flex-1 h-full">
          <ReactFlow
            nodes={nodes}
            edges={styledEdges}
            onNodesChange={onNodesChange}
            onEdgesChange={onEdgesChange}
            onConnect={onConnect}
            onInit={onInit}
            onDrop={onDrop}
            onDragOver={onDragOver}
            onNodeDoubleClick={onNodeDoubleClick}
            nodeTypes={nodeTypes}
            defaultEdgeOptions={defaultEdgeOptions}
            fitView={nodes.length === 0}
            snapToGrid
            snapGrid={[20, 20]}
            minZoom={0.1}
            maxZoom={4}
            deleteKeyCode={['Delete', 'Backspace']}
            elevateEdgesOnSelect={false}
            style={{ backgroundColor: '#0b1120' }}
          >
            <Background
              variant={BackgroundVariant.Dots}
              gap={20}
              size={1}
              color="#1e293b"
            />
            <Controls showInteractive={false} />
            <MiniMap
              nodeColor="#3B82F6"
              maskColor="rgb(15, 23, 42, 0.8)"
              pannable
              zoomable
              style={{ borderRadius: 8, border: '1px solid #334155', backgroundColor: '#1e293b' }}
            />
          </ReactFlow>
        </div>

        {/* Config panel */}
        {configNodeId && configNode && (
          <ConfigPanel
            nodeId={configNodeId}
            nodeData={configNode.data}
            onUpdateNodeData={updateNodeData}
            onClose={() => setConfigNodeId(null)}
            actionDefinitions={actionDefinitions}
            onRefreshActions={refreshActions}
          />
        )}
      </div>

      {/* ── Action Manager Modal ── */}
      {showActionManager && (
        <div className="fixed inset-0 z-[60] bg-slate-950/75 flex items-center justify-center p-4">
          <div className="w-full max-w-5xl h-[80vh] bg-slate-900 border border-slate-700 rounded-xl shadow-2xl flex flex-col overflow-hidden">
            <div className="h-12 border-b border-slate-700 px-4 flex items-center justify-between">
              <div className="flex items-center gap-2">
                <Settings size={16} className="text-slate-300" />
                <h3 className="text-sm font-semibold text-slate-100">Action Manager</h3>
              </div>
              <button
                onClick={() => setShowActionManager(false)}
                className="text-slate-400 hover:text-slate-200 transition-colors"
                title="Close"
              >
                <X size={16} />
              </button>
            </div>

            <div className="flex-1 min-h-0 flex">
              <div className="w-[260px] border-r border-slate-700 flex flex-col">
                <div className="p-3 border-b border-slate-700 flex items-center justify-between">
                  <span className="text-xs font-semibold text-slate-300">Actions</span>
                  <button
                    onClick={refreshActions}
                    className="text-slate-400 hover:text-blue-400 transition-colors"
                    title="Refresh actions"
                  >
                    <RefreshCw size={14} />
                  </button>
                </div>
                <div className="flex-1 overflow-y-auto p-2 space-y-1">
                  {actionDefinitions.map((a) => (
                    <button
                      key={a.name}
                      onClick={() => loadActionToForm(a.name)}
                      className={`w-full text-left px-2 py-2 rounded-md transition-colors ${
                        selectedActionName === a.name ? 'bg-blue-600/25 text-blue-200' : 'hover:bg-slate-800 text-slate-300'
                      }`}
                    >
                      <div className="text-xs font-medium">{a.name}</div>
                      <div className="text-[10px] text-slate-500">
                        {a.params.length} params • {a.outputs.length} outputs
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              <div className="flex-1 min-w-0 p-4 overflow-y-auto space-y-4">
                <div className="flex items-center justify-between">
                  <h4 className="text-sm font-semibold text-slate-100">
                    {selectedActionName ? `Edit: ${selectedActionName}` : 'Create New Action'}
                  </h4>
                  <div className="flex items-center gap-2">
                    <button
                      onClick={copyNewActionForm}
                      disabled={!actionForm.name.trim()}
                      className="text-xs px-2 py-1 rounded-md bg-slate-800 hover:bg-slate-700 text-slate-200 transition-colors disabled:opacity-40 disabled:cursor-not-allowed"
                    >
                      Copy New
                    </button>
                    <button
                      onClick={resetActionForm}
                      className="text-xs px-2 py-1 rounded-md bg-slate-800 hover:bg-slate-700 text-slate-200 transition-colors"
                    >
                      New Form
                    </button>
                  </div>
                </div>

                <div>
                  <label className="text-[11px] font-medium text-slate-400 mb-1 block">Name</label>
                  <input
                    type="text"
                    value={actionForm.name}
                    onChange={(e) => setActionForm((v) => ({ ...v, name: e.target.value }))}
                    className="w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5 text-xs text-slate-200
                      focus:outline-none focus:border-blue-500 transition-colors"
                    placeholder="e.g. GoTo"
                  />
                </div>

                <div>
                  <label className="text-[11px] font-medium text-slate-400 mb-1 block">Description</label>
                  <input
                    type="text"
                    value={actionForm.description}
                    onChange={(e) => setActionForm((v) => ({ ...v, description: e.target.value }))}
                    className="w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5 text-xs text-slate-200
                      focus:outline-none focus:border-blue-500 transition-colors"
                    placeholder="Human readable purpose"
                  />
                </div>

                <div>
                  <label className="text-[11px] font-medium text-slate-400 mb-1 block">Parameters (JSON array)</label>
                  <textarea
                    value={actionForm.paramsText}
                    onChange={(e) => setActionForm((v) => ({ ...v, paramsText: e.target.value }))}
                    className="w-full min-h-[140px] bg-slate-800 border border-slate-700 rounded-md px-3 py-2 text-xs text-slate-200 font-mono
                      focus:outline-none focus:border-blue-500 transition-colors"
                    placeholder='[{"name":"point_id","type":"int"}]'
                  />
                </div>

                <div>
                  <label className="text-[11px] font-medium text-slate-400 mb-1 block">Outputs (JSON array)</label>
                  <textarea
                    value={actionForm.outputsText}
                    onChange={(e) => setActionForm((v) => ({ ...v, outputsText: e.target.value }))}
                    className="w-full min-h-[120px] bg-slate-800 border border-slate-700 rounded-md px-3 py-2 text-xs text-slate-200 font-mono
                      focus:outline-none focus:border-blue-500 transition-colors"
                    placeholder='[{"id":"out-0","name":"Return 0"}]'
                  />
                </div>
              </div>
            </div>

            <div className="h-12 border-t border-slate-700 px-4 flex items-center justify-between">
              <div className="text-[10px] text-slate-500">
                Uses `pw_machine_action` via saved SQL keys.
              </div>
              <div className="flex items-center gap-2">
                <button
                  onClick={deleteActionFromForm}
                  disabled={actionManagerLoading || !actionForm.name.trim()}
                  className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
                    bg-red-600/20 hover:bg-red-600/40 text-red-400 disabled:opacity-40
                    disabled:cursor-not-allowed transition-colors"
                >
                  <Trash2 size={13} /> Delete
                </button>
                <button
                  onClick={saveActionFromForm}
                  disabled={actionManagerLoading}
                  className="flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium
                    bg-blue-600 hover:bg-blue-500 text-white disabled:opacity-40
                    disabled:cursor-not-allowed transition-colors"
                >
                  <Save size={13} /> {actionManagerLoading ? 'Saving...' : 'Save'}
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* ── Toast ── */}
      {toast && (
        <div
          className={`fixed bottom-4 right-4 px-4 py-2 rounded-lg text-sm font-medium shadow-lg z-50
            ${toast.type === 'error' ? 'bg-red-600 text-white' : 'bg-green-600 text-white'}`}
        >
          {toast.msg}
        </div>
      )}
    </div>
  );
}

// ── Page wrapper with ReactFlowProvider ──

const StateMachine = () => {
  return (
    <ReactFlowProvider>
      <StateMachineEditor />
    </ReactFlowProvider>
  );
};

export default StateMachine;
