// OAuth configuration for GitHub/Google OAuth
// Backend supports ONE provider at a time (configured via OAUTH_PROVIDER env var)
// Frontend must use the same provider as backend

const isProdHost = typeof window !== 'undefined' && window.location.hostname === 'gacongnghe.github.io';

// Get OAuth provider from environment variable or default to 'github'
// Backend must be configured with the same provider
const OAUTH_PROVIDER = process.env.REACT_APP_OAUTH_PROVIDER || 'github';

// GitHub OAuth Configuration
const GITHUB_CONFIG = {
  provider: 'github',
  clientId: process.env.REACT_APP_GITHUB_CLIENT_ID || '',
  redirectUri: isProdHost 
    ? 'https://gacongnghe.github.io/callback'
    : 'http://localhost:3000/callback',
  // IMPORTANT: user:email scope is REQUIRED for GitHub OAuth
  // Without this scope, the /user endpoint may not return email, and /user/emails will fail with 401
  scope: 'user:email',
  authorizationUrl: 'https://github.com/login/oauth/authorize',
  tokenUrl: 'https://github.com/login/oauth/access_token',
};

// Google OAuth Configuration
const GOOGLE_CONFIG = {
  provider: 'google',
  clientId: process.env.REACT_APP_GOOGLE_CLIENT_ID || '',
  redirectUri: isProdHost
    ? 'https://gacongnghe.github.io/callback'
    : 'http://localhost:3000/callback',
  scope: 'openid email profile',
  authorizationUrl: 'https://accounts.google.com/o/oauth2/v2/auth',
  tokenUrl: 'https://oauth2.googleapis.com/token',
};

// Select configuration based on provider
const OAUTH_CONFIG = OAUTH_PROVIDER === 'google' ? GOOGLE_CONFIG : GITHUB_CONFIG;

export default OAUTH_CONFIG;
export { OAUTH_PROVIDER };
