/**
 * Admin for GitHub/JWT flow: `user.role` is "admin" (any case).
 * Legacy Kanidm: `user.groups` contains admin-like strings.
 */
export function isAdminUser(user) {
  if (!user) return false;
  if (user.role != null && String(user.role).toLowerCase() === 'admin') {
    return true;
  }
  if (Array.isArray(user.groups)) {
    return user.groups.some((g) => {
      const s = String(g).toLowerCase();
      return s.includes('admin') || s.includes('administrator');
    });
  }
  return false;
}
