import React, { useState, useEffect } from 'react';
import { X, Plus, Trash2, RefreshCw, CheckCircle2, AlertCircle } from 'lucide-react';
import { buildLuaOutputs, buildPredefinedOutputs, buildPredefinedParams } from './nodeDefinitions';
import { validateLuaSyntax } from './validateLuaScript';

const inputClass = `w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5
  text-xs text-slate-200 font-mono focus:outline-none focus:border-blue-500 transition-colors`;

const labelClass = 'text-[11px] font-medium text-slate-400 mb-1 block';

function ParamEditor({ params, onChange, lockSchema = false }) {
  const addParam = () => {
    onChange([...params, { type: 'int', value: '' }]);
  };

  const removeParam = (idx) => {
    onChange(params.filter((_, i) => i !== idx));
  };

  const updateParam = (idx, field, val) => {
    const updated = params.map((p, i) => (i === idx ? { ...p, [field]: val } : p));
    onChange(updated);
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <span className={labelClass}>Parameters</span>
        {!lockSchema && (
          <button
            onClick={addParam}
            className="text-blue-400 hover:text-blue-300 transition-colors"
            title="Add parameter"
          >
            <Plus size={14} />
          </button>
        )}
      </div>
      {params.map((param, idx) => (
        <div key={idx} className="space-y-1">
          {param.name && (
            <span className="text-[10px] text-slate-400 font-mono px-0.5">{param.name}</span>
          )}
          <div className="flex items-center gap-2">
            {lockSchema ? (
              <input
                type="text"
                value={param.type || ''}
                readOnly
                className="bg-slate-800 border border-slate-700 rounded-md px-2 py-1.5
                  text-xs text-slate-400 w-20 opacity-70 cursor-not-allowed"
              />
            ) : (
              <select
                value={param.type}
                onChange={(e) => updateParam(idx, 'type', e.target.value)}
                className="bg-slate-800 border border-slate-700 rounded-md px-2 py-1.5
                  text-xs text-slate-200 focus:outline-none focus:border-blue-500 w-20"
              >
                <option value="int">int</option>
                <option value="float">float</option>
                <option value="string">string</option>
                <option value="point">point</option>
                <option value="bool">bool</option>
              </select>
            )}
            <input
              type="text"
              value={param.value}
              onChange={(e) => updateParam(idx, 'value', e.target.value)}
              placeholder={param.name || (param.type === 'point' ? 'x,y,z' : 'value')}
              className={`flex-1 ${inputClass}`}
            />
            {!lockSchema && (
              <button
                onClick={() => removeParam(idx)}
                className="text-red-400 hover:text-red-300 transition-colors shrink-0"
              >
                <Trash2 size={14} />
              </button>
            )}
          </div>
        </div>
      ))}
      {params.length === 0 && (
        <div className="text-[10px] text-slate-600 px-1">No parameters</div>
      )}
    </div>
  );
}

function OutputCodesEditor({ codes, onChange, footnote }) {
  const addCode = () => {
    const next = String(Math.max(...codes.map(Number), -1) + 1);
    onChange([...codes, next]);
  };

  const removeCode = (idx) => {
    if (codes.length <= 1) return;
    onChange(codes.filter((_, i) => i !== idx));
  };

  const updateCode = (idx, val) => {
    const updated = codes.map((c, i) => (i === idx ? val : c));
    onChange(updated);
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between">
        <span className={labelClass}>Output Return Codes</span>
        <button
          onClick={addCode}
          className="text-blue-400 hover:text-blue-300 transition-colors"
          title="Add output"
        >
          <Plus size={14} />
        </button>
      </div>
      {codes.map((code, idx) => (
        <div key={idx} className="flex items-center gap-2">
          <span className="text-[10px] text-slate-500 w-10 shrink-0">out-{code}</span>
          <input
            type="text"
            value={code}
            onChange={(e) => updateCode(idx, e.target.value)}
            className={`flex-1 ${inputClass}`}
            placeholder="0"
          />
          <button
            onClick={() => removeCode(idx)}
            disabled={codes.length <= 1}
            className="text-red-400 hover:text-red-300 disabled:opacity-30 transition-colors shrink-0"
          >
            <Trash2 size={14} />
          </button>
        </div>
      ))}
      <div className="text-[10px] text-slate-600 px-1">
        {footnote ||
          'Each code creates an output handle. Connect them to different next states.'}
      </div>
    </div>
  );
}

export function ConfigPanel({ nodeId, nodeData, onUpdateNodeData, onClose, actionDefinitions = [], onRefreshActions }) {
  const [config, setConfig] = useState({});
  const [luaSyntax, setLuaSyntax] = useState(null);

  useEffect(() => {
    if (nodeData?.config) {
      setConfig({ ...nodeData.config });
    }
  }, [nodeData]);

  useEffect(() => {
    setLuaSyntax(null);
  }, [nodeId]);

  if (!nodeId || !nodeData) return null;

  const nodeType = nodeData.type;

  const updateConfig = (key, value) => {
    const newConfig = { ...config, [key]: value };
    setConfig(newConfig);
    onUpdateNodeData(nodeId, { config: newConfig });
  };

  const updateParams = (newParams) => {
    const newConfig = { ...config, actionParams: newParams };
    setConfig(newConfig);
    onUpdateNodeData(nodeId, { config: newConfig });
  };

  const updateOutputCodes = (newCodes) => {
    const newConfig = { ...config, outputCodes: newCodes };
    setConfig(newConfig);
    onUpdateNodeData(nodeId, {
      config: newConfig,
      outputs: buildLuaOutputs(newCodes),
    });
  };

  return (
    <div className="w-[300px] flex flex-col h-full shrink-0 bg-slate-900 border-l border-slate-700">
      {/* Header */}
      <div className="p-3 border-b border-slate-700 flex items-center justify-between">
        <div>
          <div className="text-sm font-semibold text-slate-200">
            {nodeData.label}
          </div>
          <div className="text-[10px] text-slate-500 font-mono">{nodeType}</div>
        </div>
        <button
          onClick={onClose}
          className="text-slate-400 hover:text-slate-200 transition-colors"
        >
          <X size={16} />
        </button>
      </div>

      {/* Config fields */}
      <div className="flex-1 overflow-y-auto p-3 space-y-4">
        {/* State name (for all state types) */}
        {(nodeType === 'predefined' || nodeType === 'lua-script' || nodeType === 'final-state') && (
          <div>
            <label className={labelClass}>State Name</label>
            <input
              type="text"
              value={config.stateName || ''}
              onChange={(e) => updateConfig('stateName', e.target.value)}
              placeholder="e.g. gopointA"
              className={inputClass}
            />
          </div>
        )}

        {/* Predefined node config */}
        {nodeType === 'predefined' && (
          <>
            <div>
              <div className="flex items-center justify-between mb-1">
                <label className="text-[11px] font-medium text-slate-400">Action</label>
                {onRefreshActions && (
                  <button
                    onClick={onRefreshActions}
                    className="text-slate-500 hover:text-blue-400 transition-colors"
                    title="Refresh action list"
                  >
                    <RefreshCw size={12} />
                  </button>
                )}
              </div>
              {actionDefinitions.length > 0 ? (
                <select
                  value={config.actionName || ''}
                  onChange={(e) => {
                    const actionName = e.target.value;
                    const actionDef = actionDefinitions.find((a) => a.name === actionName);
                    const newParams = buildPredefinedParams(actionDef);
                    const newOutputs = buildPredefinedOutputs(actionDef);
                    const newConfig = {
                      ...config,
                      actionName,
                      actionParams: newParams,
                    };
                    setConfig(newConfig);
                    onUpdateNodeData(nodeId, { config: newConfig, outputs: newOutputs });
                  }}
                  className={`w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5
                    text-xs text-slate-200 focus:outline-none focus:border-blue-500 transition-colors`}
                >
                  <option value="">-- Select action --</option>
                  {actionDefinitions.map((a) => (
                    <option key={a.name} value={a.name}>{a.name}</option>
                  ))}
                </select>
              ) : (
                <input
                  type="text"
                  value={config.actionName || ''}
                  onChange={(e) => updateConfig('actionName', e.target.value)}
                  placeholder="e.g. GoTo"
                  className={inputClass}
                />
              )}
              {config.actionName && actionDefinitions.length > 0 && (() => {
                const ad = actionDefinitions.find((a) => a.name === config.actionName);
                return ad?.description ? (
                  <div className="text-[10px] text-slate-500 mt-1">{ad.description}</div>
                ) : null;
              })()}
            </div>
            <ParamEditor
              params={config.actionParams || []}
              onChange={updateParams}
              lockSchema
            />
          </>
        )}

        {/* Lua Script node config */}
        {nodeType === 'lua-script' && (
          <>
            <ParamEditor
              params={config.actionParams || []}
              onChange={updateParams}
            />
            <div>
              <p className="text-[10px] text-slate-500 leading-snug mb-2 px-0.5">
                The script must return two values:{' '}
                <span className="text-slate-400 font-mono">(boolean, integer)</span>. The boolean is the run
                outcome for the engine; the integer must be one of the return codes below and selects which
                output is taken.
              </p>
              <div className="flex items-center justify-between gap-2 mb-1">
                <label className={`${labelClass} mb-0`}>Lua Script</label>
                <div className="flex items-center gap-1.5 shrink-0">
                  <button
                    type="button"
                    onClick={() => {
                      const r = validateLuaSyntax(config.luaScript);
                      setLuaSyntax(r);
                    }}
                    className="text-[10px] px-2 py-0.5 rounded border border-slate-600 text-slate-300
                      hover:bg-slate-800 hover:text-slate-100 transition-colors"
                  >
                    Check syntax
                  </button>
                </div>
              </div>
              <textarea
                value={config.luaScript || ''}
                onChange={(e) => {
                  setLuaSyntax(null);
                  updateConfig('luaScript', e.target.value);
                }}
                rows={8}
                placeholder={
                  "local mode = params[1]\n" +
                  "-- bool: success for engine; int: must match a return code below\n" +
                  'return true, 0'
                }
                className={`${inputClass} resize-y min-h-[120px] ${
                  luaSyntax && !luaSyntax.ok ? 'border-amber-700/80' : ''
                } ${luaSyntax && luaSyntax.ok ? 'border-emerald-800/80' : ''}`}
              />
              {luaSyntax && luaSyntax.ok && (
                <div className="flex items-center gap-1.5 text-[10px] text-emerald-400/90 mt-1.5">
                  <CheckCircle2 size={12} className="shrink-0" />
                  <span>Syntax looks valid (Lua 5.1). Runtime must still return (bool, int).</span>
                </div>
              )}
              {luaSyntax && !luaSyntax.ok && (
                <div className="flex items-start gap-1.5 text-[10px] text-amber-400/95 mt-1.5">
                  <AlertCircle size={12} className="shrink-0 mt-0.5" />
                  <span className="break-words">
                    {typeof luaSyntax.line === 'number'
                      ? `Line ${luaSyntax.line}${
                          typeof luaSyntax.column === 'number' ? `:${luaSyntax.column}` : ''
                        }: `
                      : ''}
                    {luaSyntax.message}
                  </span>
                </div>
              )}
            </div>
            <OutputCodesEditor
              codes={config.outputCodes || ['0']}
              onChange={updateOutputCodes}
              footnote="Each value is a valid second return (integer). Use handle out-0, out-1, … to match. Add every int the script can return."
            />
          </>
        )}

        {/* Switch config */}
        {nodeType === 'switch' && (
          <>
            <div>
              <label className={labelClass}>Property</label>
              <input
                type="text"
                value={config.property || ''}
                onChange={(e) => updateConfig('property', e.target.value)}
                placeholder="e.g. action, status"
                className={inputClass}
              />
            </div>
            <div className="space-y-2">
              <div className="flex items-center justify-between">
                <span className={labelClass}>Rules</span>
                <button
                  onClick={() => {
                    const rules = config.rules || [];
                    const idx = rules.length + 1;
                    updateConfig('rules', [...rules, { value: '', port: `out-${idx}` }]);
                  }}
                  className="text-blue-400 hover:text-blue-300 transition-colors"
                  title="Add rule"
                >
                  <Plus size={14} />
                </button>
              </div>
              {(config.rules || []).map((rule, idx) => (
                <div key={idx} className="flex items-center gap-2">
                  <input
                    type="text"
                    value={rule.value}
                    onChange={(e) => {
                      const rules = [...(config.rules || [])];
                      rules[idx] = { ...rules[idx], value: e.target.value };
                      updateConfig('rules', rules);
                    }}
                    placeholder={`Case ${idx + 1} value`}
                    className={`flex-1 ${inputClass}`}
                  />
                  <button
                    onClick={() => {
                      updateConfig('rules', (config.rules || []).filter((_, i) => i !== idx));
                    }}
                    className="text-red-400 hover:text-red-300 transition-colors shrink-0"
                  >
                    <Trash2 size={14} />
                  </button>
                </div>
              ))}
            </div>
          </>
        )}

        {/* If/Else config */}
        {nodeType === 'if-else' && (
          <>
            <div>
              <label className={labelClass}>Field</label>
              <input
                type="text"
                value={config.field || ''}
                onChange={(e) => updateConfig('field', e.target.value)}
                placeholder="e.g. payload.status"
                className={inputClass}
              />
            </div>
            <div>
              <label className={labelClass}>Operator</label>
              <select
                value={config.operator || '=='}
                onChange={(e) => updateConfig('operator', e.target.value)}
                className={`w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5
                  text-xs text-slate-200 focus:outline-none focus:border-blue-500 transition-colors`}
              >
                <option value="==">== (equal)</option>
                <option value="!=">!= (not equal)</option>
                <option value=">">{'>'} (greater than)</option>
                <option value=">=">{'>='} (greater or equal)</option>
                <option value="<">{'<'} (less than)</option>
                <option value="<=">{'<='} (less or equal)</option>
              </select>
            </div>
            <div>
              <label className={labelClass}>Value</label>
              <input
                type="text"
                value={config.value || ''}
                onChange={(e) => updateConfig('value', e.target.value)}
                placeholder="e.g. success, 0"
                className={inputClass}
              />
            </div>
          </>
        )}

        {/* Loop config */}
        {nodeType === 'loop' && (
          <>
            <div>
              <label className={labelClass}>Field (iterate over)</label>
              <input
                type="text"
                value={config.field || ''}
                onChange={(e) => updateConfig('field', e.target.value)}
                placeholder="e.g. payload.items"
                className={inputClass}
              />
            </div>
            <div>
              <label className={labelClass}>Count (fixed iterations)</label>
              <input
                type="text"
                value={config.count || ''}
                onChange={(e) => updateConfig('count', e.target.value)}
                placeholder="Leave empty to iterate over field"
                className={inputClass}
              />
            </div>
          </>
        )}

        {/* Delay config */}
        {nodeType === 'delay' && (
          <>
            <div>
              <label className={labelClass}>Delay</label>
              <input
                type="number"
                value={config.delay || 1000}
                onChange={(e) => updateConfig('delay', Number(e.target.value))}
                className={inputClass}
              />
            </div>
            <div>
              <label className={labelClass}>Unit</label>
              <select
                value={config.unit || 'ms'}
                onChange={(e) => updateConfig('unit', e.target.value)}
                className={`w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5
                  text-xs text-slate-200 focus:outline-none focus:border-blue-500 transition-colors`}
              >
                <option value="ms">Milliseconds</option>
                <option value="s">Seconds</option>
                <option value="m">Minutes</option>
              </select>
            </div>
          </>
        )}

        {/* Final state config */}
        {nodeType === 'final-state' && (
          <>
            <div>
              <label className={labelClass}>Action Name</label>
              <input
                type="text"
                value={config.actionName || 'Finish'}
                onChange={(e) => updateConfig('actionName', e.target.value)}
                placeholder="Finish"
                className={inputClass}
              />
            </div>
            <ParamEditor
              params={config.actionParams || []}
              onChange={updateParams}
            />
          </>
        )}

        {/* Event config — simple events */}
        {(nodeType === 'event-start' || nodeType === 'event-disconnect' || nodeType === 'event-death') && (
          <div>
            <label className={labelClass}>Event Name</label>
            <input
              type="text"
              value={config.eventName || ''}
              readOnly
              className={`${inputClass} opacity-60 cursor-not-allowed`}
            />
            <div className="text-[10px] text-slate-600 mt-1">
              This event triggers automatically. Connect its output to the first state to handle.
            </div>
          </div>
        )}

        {/* Event config — PropertyChange */}
        {nodeType === 'event-property-change' && (
          <>
            <div>
              <label className={labelClass}>Event Name</label>
              <input
                type="text"
                value={config.eventName || ''}
                readOnly
                className={`${inputClass} opacity-60 cursor-not-allowed`}
              />
            </div>
            <div>
              <label className={labelClass}>Name</label>
              <input
                type="text"
                value={config.propertyName || ''}
                onChange={(e) => updateConfig('propertyName', e.target.value)}
                placeholder="e.g. health, level"
                className={inputClass}
              />
            </div>
            <div>
              <label className={labelClass}>Comparator</label>
              <select
                value={config.propertyComparator || '=='}
                onChange={(e) => updateConfig('propertyComparator', e.target.value)}
                className={`w-full bg-slate-800 border border-slate-700 rounded-md px-3 py-1.5
                  text-xs text-slate-200 focus:outline-none focus:border-blue-500 transition-colors`}
              >
                <option value="==">== (equal)</option>
                <option value="!=">!= (not equal)</option>
                <option value=">">{'>'} (greater than)</option>
                <option value=">=">{'>='} (greater or equal)</option>
                <option value="<">{'<'} (less than)</option>
                <option value="<=">{'<='} (less or equal)</option>
              </select>
            </div>
            <div>
              <label className={labelClass}>Value</label>
              <input
                type="text"
                value={config.propertyValue || ''}
                onChange={(e) => updateConfig('propertyValue', e.target.value)}
                placeholder="e.g. 0, max"
                className={inputClass}
              />
            </div>
            <div className="text-[10px] text-slate-600">
              Triggers when the specified property changes to the given value.
            </div>
          </>
        )}
      </div>
    </div>
  );
}
