import OAUTH_CONFIG from '../config/oauth';
import API_CONFIG from '../config/api';

// Storage keys for OAuth flow state
const STORAGE_KEYS = {
  state: 'oauth_state',
  oauthMeta: 'oauth_meta',
};

// Helper functions for PKCE
async function sha256(input) {
  const data = new TextEncoder().encode(input);
  const hash = await crypto.subtle.digest('SHA-256', data);
  return new Uint8Array(hash);
}

function base64UrlEncode(buffer) {
  let str = btoa(String.fromCharCode.apply(null, Array.from(buffer)));
  return str.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
}

// Generate code verifier (32 random bytes, base64URL encoded)
function generateCodeVerifier() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

// Generate code challenge from verifier (SHA-256 hash, base64URL encoded)
async function generateCodeChallenge(verifier) {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const digest = await crypto.subtle.digest('SHA-256', data);
  return base64UrlEncode(new Uint8Array(digest));
}

// Generate random state for CSRF protection
function generateState() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return base64UrlEncode(array);
}

async function generatePkce() {
  const codeVerifier = generateCodeVerifier();
  const codeChallenge = await generateCodeChallenge(codeVerifier);
  return { codeVerifier, codeChallenge };
}

/**
 * Start OAuth login flow
 * Redirects user to GitHub/Google OAuth provider
 */
export async function startLogin(returnTo = '/') {
  const { codeVerifier, codeChallenge } = await generatePkce();
  const state = generateState();

  // Store state and code verifier for callback
  // Use sessionStorage for code_verifier (per requirements - more secure, cleared on tab close)
  localStorage.setItem(STORAGE_KEYS.state, state);
  sessionStorage.setItem('oauth_code_verifier', codeVerifier);
  localStorage.setItem(
    STORAGE_KEYS.oauthMeta,
    JSON.stringify({ returnTo })
  );

  // Build authorization URL
  // IMPORTANT: For GitHub, scope must include 'user:email' to access user email endpoints
  const authUrl = new URL(OAUTH_CONFIG.authorizationUrl);
  authUrl.searchParams.set('response_type', 'code');
  authUrl.searchParams.set('client_id', OAUTH_CONFIG.clientId);
  authUrl.searchParams.set('redirect_uri', OAUTH_CONFIG.redirectUri);
  authUrl.searchParams.set('scope', OAUTH_CONFIG.scope); // Includes 'user:email' for GitHub
  authUrl.searchParams.set('code_challenge', codeChallenge);
  authUrl.searchParams.set('code_challenge_method', 'S256');
  authUrl.searchParams.set('state', state);

  window.location.assign(authUrl.toString());
}

/**
 * Handle OAuth callback
 * Sends authorization code to backend, which handles token exchange and returns JWT
 * This avoids CORS issues with GitHub's token endpoint
 */
export async function handleCallback() {
  const params = new URLSearchParams(window.location.search);
  const code = params.get('code');
  const returnedState = params.get('state');
  const expectedState = localStorage.getItem(STORAGE_KEYS.state);
  const codeVerifier = sessionStorage.getItem('oauth_code_verifier');

  if (!code) throw new Error('Missing authorization code');
  if (!returnedState || returnedState !== expectedState) throw new Error('Invalid state');
  if (!codeVerifier) throw new Error('Missing code verifier');

  // Send authorization code to backend
  // Backend will exchange code for OAuth token (server-side, no CORS issues)
  // Then validate OAuth token and return backend JWT
  const payload = {
    code,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    code_verifier: codeVerifier,
  };
  if (OAUTH_CONFIG.clientId) {
    payload.client_id = OAUTH_CONFIG.clientId;
  }

  const backendExchangeRes = await fetch(`${API_CONFIG.BASE_URL}${API_CONFIG.ENDPOINTS.AUTH.OAUTH_EXCHANGE}`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
    },
    body: JSON.stringify(payload),
  });

  if (!backendExchangeRes.ok) {
    const errorData = await backendExchangeRes.json().catch(() => ({ error: 'Authentication failed' }));
    throw new Error(errorData.error || 'Failed to authenticate with backend');
  }

  const backendData = await backendExchangeRes.json();
  const { token, user } = backendData;

  if (!token || !user) {
    throw new Error('Invalid response from backend');
  }

  // Store backend JWT token and user info
  // Use 'auth_token' key per requirements
  localStorage.setItem('auth_token', token);
  localStorage.setItem('user', JSON.stringify(user));
  
  // Store token expiration (24 hours from now)
  const expiresAt = Date.now() + (24 * 60 * 60 * 1000);
  localStorage.setItem('auth_token_expires_at', expiresAt.toString());

  // Cleanup OAuth flow state
  localStorage.removeItem(STORAGE_KEYS.state);
  sessionStorage.removeItem('oauth_code_verifier'); // Clean up from sessionStorage
  const meta = JSON.parse(localStorage.getItem(STORAGE_KEYS.oauthMeta) || '{}');
  localStorage.removeItem(STORAGE_KEYS.oauthMeta);

  return { user, token, returnTo: meta.returnTo || '/dashboard' };
}

/**
 * Logout - clear local storage
 * Backend JWT tokens don't need revocation, just clear local storage
 */
export async function logoutOidc() {
  localStorage.removeItem('auth_token');
  localStorage.removeItem('auth_token_expires_at');
  localStorage.removeItem('user');
  // Also clean up any OAuth state
  localStorage.removeItem(STORAGE_KEYS.state);
  sessionStorage.removeItem('oauth_code_verifier');
  localStorage.removeItem(STORAGE_KEYS.oauthMeta);
}

/**
 * Check if token is expired
 */
export function isTokenExpired() {
  const expiresAt = localStorage.getItem('auth_token_expires_at');
  if (!expiresAt) return true;
  return Date.now() > parseInt(expiresAt);
}

const oidcService = {
  startLogin,
  handleCallback,
  logoutOidc,
  isTokenExpired,
};

export default oidcService;
