import axios from 'axios';
import API_CONFIG from '../config/api';
import { isTokenExpired } from './oidcService';

// Create axios instance with default configuration
const apiClient = axios.create({
  baseURL: API_CONFIG.BASE_URL,
  timeout: API_CONFIG.TIMEOUT,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Request interceptor to add JWT token
apiClient.interceptors.request.use(
  (config) => {
    // Use 'auth_token' key per requirements
    const token = localStorage.getItem('auth_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Response interceptor to handle token expiration and errors
apiClient.interceptors.response.use(
  (response) => response,
  async (error) => {
    const originalRequest = error.config;

    // Handle 401 Unauthorized - token expired or invalid
    if (error.response?.status === 401 && !originalRequest._retry) {
      originalRequest._retry = true;

      // Backend JWT tokens expire in 24 hours and cannot be refreshed
      // User must re-authenticate with OAuth
      localStorage.removeItem('auth_token');
      localStorage.removeItem('auth_token_expires_at');
      localStorage.removeItem('user');
      
      // Redirect to login page to re-authenticate
      window.location.href = '/login';
      return Promise.reject(error);
    }

    return Promise.reject(error);
  }
);

