  // Helper method to extract error messages from backend responses
  extractErrorMessage(error, defaultMessage) {
    console.error('API Error:', error);
    
    // Handle network errors
    if (error.code === 'NETWORK_ERROR' || error.message === 'Network Error') {
      return 'Network error: Unable to connect to the server. Please check if the backend is running.';
    }
    
    // Handle timeout errors
    if (error.code === 'ECONNABORTED') {
      return 'Request timeout: The server took too long to respond.';
    }
    
    // Handle HTTP status errors
    if (error.response) {
      const status = error.response.status;
      const data = error.response.data;
      
      // Try different possible error message fields
      const errorMessage = data?.message || 
                          data?.error || 
                          data?.detail ||
                          data?.msg ||
                          data?.error_message ||
                          data?.error_description;
      
      if (errorMessage) {
        return errorMessage;
      }
      
      // Fallback to status-based messages
      switch (status) {
        case 400:
          return 'Bad request: Invalid data provided.';
        case 401:
          return 'Unauthorized: Invalid credentials.';
        case 403:
          return 'Forbidden: Access denied.';
        case 404:
          return 'Not found: The requested resource was not found.';
        case 500:
          return 'Server error: Internal server error occurred.';
        default:
          return `HTTP ${status}: ${JSON.stringify(data) || 'Unknown error'}`;
      }
    }
    
    // Handle other errors
    if (error.message) {
      return error.message;
    }
    
    return defaultMessage;
  }

  // Authentication methods
  async login(credentials) {
    try {
      const response = await apiClient.post(API_CONFIG.ENDPOINTS.AUTH.LOGIN, credentials);
      const { token, user } = response.data;
      
      // Use 'auth_token' key per requirements
      localStorage.setItem('auth_token', token);
      localStorage.setItem('user', JSON.stringify(user));
      
      // Store token expiration (24 hours from now)
      const expiresAt = Date.now() + (24 * 60 * 60 * 1000);
      localStorage.setItem('auth_token_expires_at', expiresAt.toString());
      
      return response.data;
    } catch (error) {
      throw new Error(this.extractErrorMessage(error, 'Login failed'));
    }
  }

