import React, { createContext, useContext, useState, useEffect } from 'react';
import apiService from '../services/apiService';
import oidcService from '../services/oidcService';

const AuthContext = createContext();

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Hydrate from localStorage set by OAuth callback
    try {
      // Use 'auth_token' key per requirements
      const token = localStorage.getItem('auth_token');
      const storedUser = apiService.getCurrentUser();
      
      // Check if token exists and is not expired
      if (token && storedUser && apiService.isAuthenticated()) {
        setUser(storedUser);
      } else {
        // Token expired or invalid - clear storage
        if (token) {
          apiService.logout();
        }
      }
    } catch (err) {
      console.error('Auth hydration failed:', err);
      apiService.logout();
    } finally {
      setLoading(false);
    }
  }, []);

  const login = async (returnTo = '/dashboard') => {
    setError(null);
    setLoading(true);
    try {
      await oidcService.startLogin(returnTo);
    } catch (err) {
      setError(err.message);
      setLoading(false);
      throw err;
    }
  };

  const register = async (userData) => {
    try {
      setError(null);
      setLoading(true);
      
      const response = await apiService.register(userData);
      return response;
    } catch (err) {
      setError(err.message);
      throw err;
    } finally {
      setLoading(false);
    }
  };

  const logout = async () => {
    try {
      await oidcService.logoutOidc();
      setUser(null);
      setError(null);
    } catch (err) {
      console.error('Logout error:', err);
      // Force logout even if API call fails
      setUser(null);
      setError(null);
      // Clear storage
      apiService.logout();
    }
  };

  const updateProfile = async (profileData) => {
    try {
      setError(null);
      // If profileData is a full user object (from getUserProfile), update directly
      // Otherwise, try to update via API
      if (profileData && (profileData.role || profileData.email)) {
        // This looks like a full user object from backend
        setUser(profileData);
        // Also update localStorage
        localStorage.setItem('user', JSON.stringify(profileData));
        return { success: true };
      }
      
      // Otherwise, try API update
      const response = await apiService.updateUserProfile(profileData);
      
      // Update local user state
      if (response.success) {
        setUser(prevUser => ({ ...prevUser, ...profileData }));
      }
      
      return response;
    } catch (err) {
      setError(err.message);
      throw err;
    }
  };

  const clearError = () => {
    setError(null);
  };

  const value = {
    user,
    loading,
    error,
    login,
    register,
    logout,
    updateProfile,
    clearError,
    isAuthenticated: !!user && apiService.isAuthenticated(),
    // Allow OAuth callback to atomically set the session
    completeOidcLogin: (authenticatedUser) => {
      setUser(authenticatedUser);
      setError(null);
      setLoading(false);
    },
  };

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};
