import React, { useState, useEffect, useRef } from 'react';
import Editor from '@monaco-editor/react';
import apiService from '../services/apiService';
import LoadingSpinner from '../components/LoadingSpinner';
import Notification from '../components/Notification';

const DEFAULT_BASH_SCRIPT = `#!/bin/bash
# Enter your Bash script here
# Example:
# echo "Hello \${NAME:-World}"

echo "Hello \${NAME:-World}"
`;

const DEFAULT_PARAMS = JSON.stringify({ NAME: 'World' }, null, 2);

const BashStudio = () => {
  const [databases, setDatabases] = useState([]);
  const [selectedDatabase, setSelectedDatabase] = useState('');
  const [bashScript, setBashScript] = useState(DEFAULT_BASH_SCRIPT);
  const [scriptParams, setScriptParams] = useState(DEFAULT_PARAMS);
  const [executionTimeout, setExecutionTimeout] = useState('');
  const [scriptResults, setScriptResults] = useState(null);
  const [loading, setLoading] = useState(false);
  const [notification, setNotification] = useState(null);
  const [savedScripts, setSavedScripts] = useState([]);
  const [showSaveScript, setShowSaveScript] = useState(false);
  const [scriptName, setScriptName] = useState('');
  const [scriptRole, setScriptRole] = useState('user');
  const [scriptTimeout, setScriptTimeout] = useState('');
  const [selectedSavedScript, setSelectedSavedScript] = useState(null);
  const [editingRoleForScript, setEditingRoleForScript] = useState(null);
  const [tempRoleValue, setTempRoleValue] = useState('');

  const editorRef = useRef(null);
  const jsonEditorRef = useRef(null);

  useEffect(() => {
    loadDatabases();
  }, []);

  useEffect(() => {
    if (selectedDatabase) {
      loadSavedScripts();
    } else {
      setSavedScripts([]);
    }
  }, [selectedDatabase]);

  const loadDatabases = async () => {
    try {
      setLoading(true);
      const data = await apiService.getDatabases();
      setDatabases(data);
      if (data.length > 0 && !selectedDatabase) {
        setSelectedDatabase(data[0].name);
      }
    } catch (error) {
      showNotification(error.message, 'error');
    } finally {
      setLoading(false);
    }
  };

  const loadSavedScripts = async () => {
    if (!selectedDatabase) return;

    try {
      const data = await apiService.getBashScriptStore(selectedDatabase);
      setSavedScripts(data || []);
    } catch (error) {
      showNotification(error.message, 'error');
    }
  };

  const parseParams = () => {
    if (!scriptParams.trim()) {
      return {};
    }

    try {
      return JSON.parse(scriptParams);
    } catch (error) {
      throw new Error('Invalid JSON in script parameters');
    }
  };

  const parseTimeoutValue = (value) => {
    if (!value.trim()) {
      return null;
    }

    const parsed = Number.parseInt(value, 10);
    if (Number.isNaN(parsed) || parsed < 0) {
      throw new Error('Timeout must be a non-negative integer');
    }

    return parsed;
  };

  const handleExecuteScript = async () => {
    if (!selectedDatabase) {
      showNotification('Please select a database first', 'error');
      return;
    }

    if (!bashScript.trim()) {
      showNotification('Please enter a Bash script', 'error');
      return;
    }

    try {
      setLoading(true);
      const params = parseParams();
      const timeoutSeconds = parseTimeoutValue(executionTimeout);

      const result = await apiService.executeBashScript(
        selectedDatabase,
        bashScript,
        params,
        timeoutSeconds
      );

      setScriptResults(result);
      showNotification('Script executed successfully', 'success');
    } catch (error) {
      showNotification(error.message, 'error');
      setScriptResults({
        error: error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  const handleExecuteSavedScript = async (scriptKey) => {
    if (!selectedDatabase) {
      showNotification('Please select a database first', 'error');
      return;
    }

    try {
      setLoading(true);
      const params = parseParams();
      const timeoutSeconds = parseTimeoutValue(executionTimeout);

      const result = await apiService.executeSavedBashScript(
        selectedDatabase,
        scriptKey,
        params,
        timeoutSeconds
      );

      setScriptResults(result);
      showNotification('Saved script executed successfully', 'success');
    } catch (error) {
      showNotification(error.message, 'error');
      setScriptResults({
        error: error.message,
      });
    } finally {
      setLoading(false);
    }
  };

  const handleSaveScript = async () => {
    if (!selectedDatabase) {
      showNotification('Please select a database first', 'error');
      return;
    }

    if (!scriptName.trim()) {
      showNotification('Please enter a script name', 'error');
      return;
    }

    if (!bashScript.trim()) {
      showNotification('Please enter a Bash script', 'error');
      return;
    }

    let timeoutSeconds = null;
    try {
      timeoutSeconds = parseTimeoutValue(scriptTimeout);
    } catch (error) {
      showNotification(error.message, 'error');
      return;
    }

    try {
      setLoading(true);
      const scriptData = {
        script_key: scriptName,
        script: bashScript,
        required_role: scriptRole,
      };

      if (timeoutSeconds !== null) {
        scriptData.timeout_seconds = timeoutSeconds;
      }

      if (selectedSavedScript) {
        const updateData = {
          script: bashScript,
          required_role: scriptRole,
        };

        if (timeoutSeconds !== null) {
          updateData.timeout_seconds = timeoutSeconds;
        } else {
          updateData.timeout_seconds = null;
        }

        await apiService.updateBashScriptStore(
          selectedDatabase,
          selectedSavedScript.script_key,
          updateData
        );
        showNotification('Script updated successfully', 'success');
      } else {
        await apiService.createBashScriptStore(selectedDatabase, scriptData);
        showNotification('Script saved successfully', 'success');
      }

      setShowSaveScript(false);
      setScriptName('');
      setScriptRole('user');
      setScriptTimeout('');
      setSelectedSavedScript(null);
      loadSavedScripts();
    } catch (error) {
      showNotification(error.message, 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleLoadScript = (script) => {
    setBashScript(script.script);
    setSelectedSavedScript(script);
    setScriptName(script.script_key);
    setScriptRole(script.required_role);
    setScriptTimeout(
      script.timeout_seconds !== null && script.timeout_seconds !== undefined
        ? String(script.timeout_seconds)
        : ''
    );
    showNotification(`Loaded script: ${script.script_key}`, 'success');
  };

  const handleDeleteScript = async (scriptKey) => {
    if (!window.confirm(`Are you sure you want to delete the script "${scriptKey}"?`)) {
      return;
    }

    try {
      setLoading(true);
      await apiService.deleteBashScriptStore(selectedDatabase, scriptKey);
      showNotification('Script deleted successfully', 'success');

      if (selectedSavedScript?.script_key === scriptKey) {
        setBashScript(DEFAULT_BASH_SCRIPT);
        setSelectedSavedScript(null);
        setScriptName('');
        setScriptRole('user');
        setScriptTimeout('');
      }

      loadSavedScripts();
    } catch (error) {
      showNotification(error.message, 'error');
    } finally {
      setLoading(false);
    }
  };

  const handleUpdateRole = async (scriptKey, newRole) => {
    try {
      await apiService.updateBashScriptStore(selectedDatabase, scriptKey, {
        required_role: newRole,
      });
      showNotification('Script role updated successfully', 'success');
      setEditingRoleForScript(null);
      setTempRoleValue('');
      loadSavedScripts();
    } catch (error) {
      showNotification(error.message, 'error');
    }
  };

  const handleNewScript = () => {
    setBashScript(DEFAULT_BASH_SCRIPT);
    setScriptParams(DEFAULT_PARAMS);
    setExecutionTimeout('');
    setScriptResults(null);
    setSelectedSavedScript(null);
    setScriptName('');
    setScriptRole('user');
    setScriptTimeout('');
    showNotification('New script editor ready', 'info');
  };

  const showNotification = (message, type = 'info') => {
    setNotification({ message, type });
  };

  const clearNotification = () => {
    setNotification(null);
  };

  const handleEditorDidMount = (editor) => {
    editorRef.current = editor;
  };

  const handleJsonEditorDidMount = (editor) => {
    jsonEditorRef.current = editor;
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      {notification && (
        <Notification message={notification.message} type={notification.type} onClose={clearNotification} />
      )}

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="bg-white shadow rounded-lg p-6">
          <div className="flex items-center justify-between mb-6">
            <h1 className="text-3xl font-bold text-gray-900">🐚 Bash Studio</h1>
            <div className="flex items-center space-x-4">
              <button
                onClick={handleNewScript}
                className="bg-green-600 text-white px-4 py-2 rounded-md hover:bg-green-700 transition-colors flex items-center space-x-2"
              >
                <span>📝</span>
                <span>New Script</span>
              </button>
            </div>
          </div>

          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-2">Select Database</label>
            <select
              value={selectedDatabase}
              onChange={(event) => setSelectedDatabase(event.target.value)}
              className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="">-- Select a database --</option>
              {databases.map((db) => (
                <option key={db.name} value={db.name}>
                  {db.name}
                </option>
              ))}
            </select>
          </div>

          {selectedDatabase && (
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
              <div className="lg:col-span-2 space-y-6">
                <div>
                  <div className="flex items-center justify-between mb-2">
                    <label className="block text-sm font-medium text-gray-700">Bash Script</label>
                    <button
                      onClick={() => setShowSaveScript(true)}
                      className="text-sm text-blue-600 hover:text-blue-700 flex items-center space-x-1"
                    >
                      <span>💾</span>
                      <span>Save Script</span>
                    </button>
                  </div>
                  <div className="border border-gray-300 rounded-md overflow-hidden">
                    <Editor
                      height="400px"
                      defaultLanguage="shell"
                      theme="vs-dark"
                      value={bashScript}
                      onChange={(value) => setBashScript(value || '')}
                      onMount={handleEditorDidMount}
                      options={{
                        minimap: { enabled: false },
                        fontSize: 14,
                        lineNumbers: 'on',
                        roundedSelection: false,
                        scrollBeyondLastLine: false,
                        readOnly: false,
                        automaticLayout: true,
                        tabSize: 2,
                        insertSpaces: true,
                        wordWrap: 'on',
                        wrappingIndent: 'indent',
                        lineDecorationsWidth: 5,
                        lineNumbersMinChars: 3,
                        renderLineHighlight: 'all',
                        scrollbar: {
                          verticalScrollbarSize: 10,
                          horizontalScrollbarSize: 10,
                        },
                      }}
                    />
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Script Parameters (JSON)</label>
                    <div className="border border-gray-300 rounded-md overflow-hidden">
                      <Editor
                        height="150px"
                        defaultLanguage="json"
                        theme="light"
                        value={scriptParams}
                        onChange={(value) => setScriptParams(value || '')}
                        onMount={handleJsonEditorDidMount}
                        options={{
                          minimap: { enabled: false },
                          fontSize: 13,
                          lineNumbers: 'off',
                          roundedSelection: false,
                          scrollBeyondLastLine: false,
                          readOnly: false,
                          automaticLayout: true,
                          tabSize: 2,
                          insertSpaces: true,
                          wordWrap: 'on',
                          lineDecorationsWidth: 0,
                          folding: false,
                          renderLineHighlight: 'none',
                          scrollbar: {
                            verticalScrollbarSize: 8,
                            horizontalScrollbarSize: 8,
                          },
                        }}
                      />
                    </div>
                    <p className="text-xs text-gray-500 mt-2">
                      Parameters are passed as environment variables. Nested fields are converted to JSON strings.
                    </p>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Execution Timeout (seconds)</label>
                    <input
                      type="number"
                      min="0"
                      placeholder="Optional"
                      value={executionTimeout}
                      onChange={(event) => setExecutionTimeout(event.target.value)}
                      className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                    <p className="text-xs text-gray-500 mt-2">
                      Leave blank to use the default timeout configured on the server.
                    </p>
                  </div>
                </div>

                <div className="flex space-x-4">
                  <button
                    onClick={handleExecuteScript}
                    disabled={loading || !bashScript.trim()}
                    className="flex-1 bg-blue-600 text-white px-6 py-3 rounded-md hover:bg-blue-700 disabled:bg-gray-400 disabled:cursor-not-allowed transition-colors flex items-center justify-center space-x-2"
                  >
                    {loading ? (
                      <>
                        <LoadingSpinner size="small" />
                        <span>Executing...</span>
                      </>
                    ) : (
                      <>
                        <span>▶️</span>
                        <span>Execute Script</span>
                      </>
                    )}
                  </button>
                </div>

                {scriptResults && (
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">Results</label>
                    <div className="bg-gray-50 border border-gray-300 rounded-md p-4 space-y-4">
                      {scriptResults.error ? (
                        <div className="text-red-600">
                          <strong>Error:</strong> {scriptResults.error}
                        </div>
                      ) : (
                        <>
                          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 text-sm text-gray-700">
                            <div>
                              <strong>Status:</strong>{' '}
                              <span className={scriptResults.success ? 'text-green-600' : 'text-red-600'}>
                                {scriptResults.success ? 'Success' : 'Failed'}
                              </span>
                            </div>
                            <div>
                              <strong>Exit Code:</strong>{' '}
                              {scriptResults.exit_code !== null && scriptResults.exit_code !== undefined
                                ? scriptResults.exit_code
                                : 'N/A'}
                            </div>
                            <div>
                              <strong>Timeout:</strong>{' '}
                              {scriptResults.timeout_seconds !== null && scriptResults.timeout_seconds !== undefined
                                ? `${scriptResults.timeout_seconds}s`
                                : 'N/A'}
                            </div>
                          </div>
                          <div>
                            <strong className="text-sm text-gray-700">STDOUT</strong>
                            <pre className="mt-2 bg-white p-4 rounded border border-gray-200 overflow-auto max-h-64 text-sm whitespace-pre-wrap">
                              {scriptResults.stdout || ''}
                            </pre>
                          </div>
                          <div>
                            <strong className="text-sm text-gray-700">STDERR</strong>
                            <pre className="mt-2 bg-white p-4 rounded border border-gray-200 overflow-auto max-h-64 text-sm whitespace-pre-wrap text-red-600">
                              {scriptResults.stderr || ''}
                            </pre>
                          </div>
                        </>
                      )}
                    </div>
                  </div>
                )}
              </div>

              <div className="lg:col-span-1">
                <div className="bg-gray-50 border border-gray-300 rounded-md p-4 sticky top-4">
                  <h3 className="text-lg font-semibold text-gray-800 mb-4">Saved Scripts</h3>

                  {savedScripts.length === 0 ? (
                    <p className="text-gray-500 text-sm">No saved scripts yet</p>
                  ) : (
                    <div className="space-y-2 max-h-[600px] overflow-y-auto">
                      {savedScripts.map((script) => (
                        <div
                          key={script.script_key}
                          className="bg-white border border-gray-200 rounded-md p-3 hover:shadow-md transition-shadow"
                        >
                          <div className="flex items-start justify-between mb-2">
                            <h4 className="font-medium text-gray-900 text-sm break-all">{script.script_key}</h4>
                            <button
                              onClick={() => handleDeleteScript(script.script_key)}
                              className="text-red-600 hover:text-red-700 ml-2 flex-shrink-0"
                              title="Delete script"
                            >
                              🗑️
                            </button>
                          </div>

                          <div className="mb-2 space-y-2">
                            {editingRoleForScript === script.script_key ? (
                              <div className="flex items-center space-x-2">
                                <select
                                  value={tempRoleValue}
                                  onChange={(event) => setTempRoleValue(event.target.value)}
                                  className="flex-1 px-2 py-1 text-xs border border-gray-300 rounded focus:outline-none focus:ring-1 focus:ring-blue-500"
                                >
                                  <option value="admin">admin</option>
                                  <option value="moderator">moderator</option>
                                  <option value="robot">robot</option>
                                  <option value="user">user</option>
                                  <option value="guest">guest</option>
                                </select>
                                <button
                                  onClick={() => handleUpdateRole(script.script_key, tempRoleValue)}
                                  className="px-2 py-1 text-xs bg-green-600 text-white rounded hover:bg-green-700"
                                  title="Save role"
                                >
                                  ✓
                                </button>
                                <button
                                  onClick={() => {
                                    setEditingRoleForScript(null);
                                    setTempRoleValue('');
                                  }}
                                  className="px-2 py-1 text-xs bg-gray-600 text-white rounded hover:bg-gray-700"
                                  title="Cancel"
                                >
                                  ✗
                                </button>
                              </div>
                            ) : (
                              <div className="flex items-center space-x-2">
                                <span className="text-xs px-2 py-1 bg-purple-100 text-purple-700 rounded">
                                  {script.required_role}
                                </span>
                                <button
                                  onClick={() => {
                                    setEditingRoleForScript(script.script_key);
                                    setTempRoleValue(script.required_role);
                                  }}
                                  className="text-gray-500 hover:text-gray-700 text-xs"
                                  title="Edit role"
                                >
                                  ✏️
                                </button>
                              </div>
                            )}
                            <div className="text-xs text-gray-600">
                              <strong>Timeout:</strong>{' '}
                              {script.timeout_seconds !== null && script.timeout_seconds !== undefined
                                ? `${script.timeout_seconds}s`
                                : 'Default'}
                            </div>
                          </div>

                          <div className="flex space-x-2">
                            <button
                              onClick={() => handleLoadScript(script)}
                              className="flex-1 bg-blue-600 text-white px-3 py-1 rounded text-xs hover:bg-blue-700 transition-colors"
                            >
                              Load
                            </button>
                            <button
                              onClick={() => handleExecuteSavedScript(script.script_key)}
                              className="flex-1 bg-green-600 text-white px-3 py-1 rounded text-xs hover:bg-green-700 transition-colors"
                            >
                              Execute
                            </button>
                          </div>

                          <div className="mt-2 text-xs text-gray-500 space-y-1">
                            <div>Created: {new Date(script.created_at).toLocaleString()}</div>
                            <div>Updated: {new Date(script.updated_at).toLocaleString()}</div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>

      {showSaveScript && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center p-4 z-50">
          <div className="bg-white rounded-lg p-6 max-w-md w-full">
            <h3 className="text-xl font-bold text-gray-900 mb-4">
              {selectedSavedScript ? 'Update Script' : 'Save Script'}
            </h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Script Name (Key)</label>
                <input
                  type="text"
                  value={scriptName}
                  onChange={(event) => setScriptName(event.target.value)}
                  disabled={!!selectedSavedScript}
                  placeholder="check_disk_space"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-gray-100"
                />
                {selectedSavedScript && (
                  <p className="text-xs text-gray-500 mt-1">Script name cannot be changed</p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Required Role</label>
                <select
                  value={scriptRole}
                  onChange={(event) => setScriptRole(event.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                >
                  <option value="admin">Admin</option>
                  <option value="moderator">Moderator</option>
                  <option value="robot">Robot</option>
                  <option value="user">User</option>
                  <option value="guest">Guest</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">Default Timeout (seconds)</label>
                <input
                  type="number"
                  min="0"
                  placeholder="Optional"
                  value={scriptTimeout}
                  onChange={(event) => setScriptTimeout(event.target.value)}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                />
                <p className="text-xs text-gray-500 mt-1">
                  Leave blank to use the server default or clear the timeout on update.
                </p>
              </div>

              <div className="flex space-x-4">
                <button
                  onClick={handleSaveScript}
                  disabled={loading}
                  className="flex-1 bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 disabled:bg-gray-400 transition-colors"
                >
                  {loading ? 'Saving...' : selectedSavedScript ? 'Update' : 'Save'}
                </button>
                <button
                  onClick={() => {
                    setShowSaveScript(false);
                    if (!selectedSavedScript) {
                      setScriptName('');
                      setScriptRole('user');
                      setScriptTimeout('');
                    }
                  }}
                  className="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-md hover:bg-gray-400 transition-colors"
                >
                  Cancel
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BashStudio;


