import luaparse from 'luaparse';

/**
 * Client-side Lua parse check (luaparse). Matches Lua grammar; runtime/API behavior is not verified.
 * @param {string} [source]
 * @param {{ luaVersion?: string }} [opts]
 * @returns {{ ok: true } | { ok: false, message: string, line?: number, column?: number }}
 */
export function validateLuaSyntax(source, opts = {}) {
  const s = source == null ? '' : String(source);
  if (s.trim() === '') {
    return { ok: true };
  }
  const luaVersion = opts.luaVersion || '5.1';
  try {
    luaparse.parse(s, { comments: true, scope: false, luaVersion, encodingMode: 'none' });
    return { ok: true };
  } catch (e) {
    return {
      ok: false,
      message: e && e.message ? e.message : String(e),
      line: e && typeof e.line === 'number' ? e.line : undefined,
      column: e && typeof e.column === 'number' ? e.column : undefined,
    };
  }
}
