import React, { memo, useCallback } from 'react';
import { Handle, Position, useReactFlow } from '@xyflow/react';
import { X } from 'lucide-react';
import { NODE_ICON_MAP, CATEGORY_COLORS } from './nodeDefinitions';

const HEADER_H = 36;
const TYPE_H = 20;
const ROW_H = 20;
const PAD_BOTTOM = 4;

function getPortColor(portId) {
  if (portId === 'error') return '#EF4444';
  return '#94A3B8';
}

function isEventType(nodeType) {
  return nodeType?.startsWith('event-');
}

function getNodeStyle(nodeType) {
  switch (nodeType) {
    case 'predefined':
      return { borderColor: '#3B82F6', bgTint: 'rgba(59,130,246,0.08)' };
    case 'lua-script':
      return { borderColor: '#8B5CF6', bgTint: 'rgba(139,92,246,0.08)' };
    case 'final-state':
      return { borderColor: '#EF4444', bgTint: 'rgba(239,68,68,0.08)' };
    case 'switch':
      return { borderColor: '#8B5CF6', bgTint: 'rgba(139,92,246,0.08)' };
    case 'if-else':
      return { borderColor: '#A78BFA', bgTint: 'rgba(167,139,250,0.08)' };
    case 'loop':
      return { borderColor: '#7C3AED', bgTint: 'rgba(124,58,237,0.08)' };
    case 'delay':
      return { borderColor: '#6D28D9', bgTint: 'rgba(109,40,217,0.08)' };
    case 'event-start':
      return { borderColor: '#F59E0B', bgTint: 'rgba(245,158,11,0.08)' };
    case 'event-disconnect':
      return { borderColor: '#F97316', bgTint: 'rgba(249,115,22,0.08)' };
    case 'event-death':
      return { borderColor: '#DC2626', bgTint: 'rgba(220,38,38,0.08)' };
    case 'event-property-change':
      return { borderColor: '#06B6D4', bgTint: 'rgba(6,182,212,0.08)' };
    default:
      return { borderColor: '#3B82F6', bgTint: 'rgba(59,130,246,0.08)' };
  }
}

function StateMachineNodeComponent({ id, data, selected }) {
  const { deleteElements } = useReactFlow();
  const nodeData = data || {};

  const icon = nodeData.icon || 'Cog';
  const category = nodeData.category || 'state';
  const nodeType = nodeData.type || 'predefined';
  const config = nodeData.config || {};

  const displayLabel = config.stateName || config.propertyName || config.eventName || nodeData.label || 'Node';
  const categoryColor = CATEGORY_COLORS[category] || '#3B82F6';
  const { borderColor, bgTint } = getNodeStyle(nodeType);

  const inputs = Array.isArray(nodeData.inputs) ? nodeData.inputs : [];
  const outputs = Array.isArray(nodeData.outputs) ? nodeData.outputs : [];
  const maxPorts = Math.max(inputs.length, outputs.length);

  const Icon = NODE_ICON_MAP[icon];

  const handleDelete = useCallback((e) => {
    e.stopPropagation();
    deleteElements({ nodes: [{ id }] });
  }, [id, deleteElements]);

  let subtitle = '';
  if (nodeType === 'predefined') {
    subtitle = config.actionName || 'predefined';
  } else if (nodeType === 'lua-script') {
    subtitle = 'return bool, int';
  } else if (nodeType === 'final-state') {
    subtitle = config.actionName || 'Finish';
  } else if (nodeType === 'switch') {
    subtitle = config.property ? `on: ${config.property}` : 'switch';
  } else if (nodeType === 'if-else') {
    subtitle = config.field ? `${config.field} ${config.operator || '=='} ${config.value || '?'}` : 'if/else';
  } else if (nodeType === 'loop') {
    subtitle = config.field ? `each: ${config.field}` : (config.count ? `${config.count}x` : 'loop');
  } else if (nodeType === 'delay') {
    subtitle = `${config.delay || 0}${config.unit || 'ms'}`;
  } else if (nodeType === 'event-property-change') {
    subtitle = config.propertyName ? `${config.propertyName} ${config.propertyComparator || '=='} ${config.propertyValue || '?'}` : 'PropertyChange';
  } else if (isEventType(nodeType)) {
    subtitle = config.eventName || nodeType;
  }

  return (
    <div
      className={`
        relative rounded-lg border-2 min-w-[170px] cursor-pointer
        transition-all duration-150 group
        ${selected ? 'ring-2 ring-blue-400 ring-offset-1 ring-offset-slate-950' : ''}
      `}
      style={{
        backgroundColor: '#1e293b',
        borderColor: borderColor,
      }}
    >
      {/* Delete button */}
      <button
        onClick={handleDelete}
        className="absolute -top-2 -right-2 w-5 h-5 rounded-full bg-red-600 hover:bg-red-500
          flex items-center justify-center opacity-0 group-hover:opacity-100
          transition-opacity z-10 shadow-md"
      >
        <X size={12} className="text-white" />
      </button>

      {/* Header */}
      <div
        className="flex items-center gap-2 px-3 rounded-t-md"
        style={{ height: HEADER_H, backgroundColor: bgTint }}
      >
        <div
          className="w-6 h-6 rounded flex items-center justify-center shrink-0"
          style={{ backgroundColor: `${categoryColor}30` }}
        >
          {Icon ? <Icon size={14} style={{ color: categoryColor }} /> : null}
        </div>
        <span className="text-xs font-medium text-slate-200 truncate">
          {displayLabel}
        </span>
      </div>

      {/* Body */}
      <div style={{ paddingBottom: PAD_BOTTOM }}>
        {/* Type label */}
        <div className="px-3 flex items-center" style={{ height: TYPE_H }}>
          <span className="text-[10px] text-slate-500 font-mono truncate">
            {subtitle}
          </span>
        </div>

        {/* Port rows */}
        {Array.from({ length: maxPorts }, (_, i) => {
          const inp = inputs[i];
          const out = outputs[i];
          return (
            <div
              key={inp?.id || out?.id || `port-${i}`}
              className="flex items-center justify-between px-3 gap-4"
              style={{ height: ROW_H }}
            >
              <span
                className="text-[9px] font-mono truncate"
                style={{ color: inp ? getPortColor(inp.id) : 'transparent' }}
              >
                {inp?.name || ''}
              </span>
              <span
                className="text-[9px] font-mono truncate text-right"
                style={{ color: out ? getPortColor(out.id) : 'transparent' }}
              >
                {out?.name || ''}
              </span>
            </div>
          );
        })}
      </div>

      {/* Input handles */}
      {inputs.map((port, i) => (
        <Handle
          key={`in-${port.id}`}
          type="target"
          position={Position.Left}
          id={port.id}
          style={{
            top: HEADER_H + TYPE_H + i * ROW_H + ROW_H / 2,
            background: getPortColor(port.id),
            width: 10,
            height: 10,
            border: '2px solid #1e293b',
          }}
        />
      ))}

      {/* Output handles */}
      {outputs.map((port, i) => (
        <Handle
          key={`out-${port.id}`}
          type="source"
          position={Position.Right}
          id={port.id}
          style={{
            top: HEADER_H + TYPE_H + i * ROW_H + ROW_H / 2,
            background: getPortColor(port.id),
            width: 10,
            height: 10,
            border: '2px solid #1e293b',
          }}
        />
      ))}
    </div>
  );
}

export const StateMachineNode = memo(StateMachineNodeComponent);
