import React, { useState, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import LoadingSpinner from '../components/LoadingSpinner';
import Notification from '../components/Notification';
import apiService from '../services/apiService';

const Profile = () => {
  const { user, updateProfile } = useAuth();
  const [notification, setNotification] = useState({ show: false, type: '', message: '' });
  const [activeTab, setActiveTab] = useState('profile');
  const [showJWT, setShowJWT] = useState(false);
  const [loadingUser, setLoadingUser] = useState(false);
  
  // API Key management state
  const [apiKeys, setApiKeys] = useState([]);
  const [loadingApiKeys, setLoadingApiKeys] = useState(false);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [newApiKey, setNewApiKey] = useState({ role: 'robot', name: '' });
  const [createdApiKey, setCreatedApiKey] = useState(null);

  // Refresh user data from backend on mount to ensure role is up-to-date
  useEffect(() => {
    const refreshUserData = async () => {
      try {
        setLoadingUser(true);
        const userData = await apiService.getUserProfile();
        // Update user in context if role changed
        if (userData && userData.role && userData.role !== user?.role) {
          updateProfile(userData);
        }
      } catch (error) {
        console.error('Failed to refresh user data:', error);
        // Don't show error to user, just use cached data
      } finally {
        setLoadingUser(false);
      }
    };

    // Only refresh if we have a user but no role (might be stale data)
    if (user && !user.role) {
      refreshUserData();
    }
  }, [user, updateProfile]);

  const showNotification = (type, message) => {
    setNotification({ show: true, type, message });
    setTimeout(() => {
      setNotification({ show: false, type: '', message: '' });
    }, 5000);
  };

  // JWT utility functions
  const getJWTToken = () => {
    // Try to get JWT from localStorage or sessionStorage
    // Use 'auth_token' key per requirements (primary)
    const token = localStorage.getItem('auth_token') ||
                  localStorage.getItem('token') || // Fallback for backward compatibility
                  localStorage.getItem('access_token') || 
                  sessionStorage.getItem('auth_token') ||
                  sessionStorage.getItem('token') ||
                  sessionStorage.getItem('access_token');
    return token;
  };

  const maskJWT = (token) => {
    if (!token) return 'No token available';
    if (token.length <= 20) return token;
    return token.substring(0, 10) + '...' + token.substring(token.length - 10);
  };

  const copyJWTToClipboard = async () => {
    const token = getJWTToken();
    if (!token) {
      showNotification('error', 'No JWT token available to copy');
      return;
    }
    
    try {
      await navigator.clipboard.writeText(token);
      showNotification('success', 'JWT token copied to clipboard');
    } catch (err) {
      showNotification('error', 'Failed to copy JWT token');
    }
  };

  // Password changes are managed in the OAuth provider (GitHub/Google) portal

  const getUserRole = (user) => {
    if (user?.role) {
      return user.role;
    }
    return 'user';
  };

  const getRoleBadgeColor = (role) => {
    switch (role?.toLowerCase()) {
      case 'admin':
        return 'bg-red-100 text-red-800';
      case 'manager':
        return 'bg-yellow-100 text-yellow-800';
      case 'robot':
        return 'bg-purple-100 text-purple-800';
      case 'user':
        return 'bg-blue-100 text-blue-800';
      default:
        return 'bg-gray-100 text-gray-800';
    }
  };

  // API Key management functions
  const loadApiKeys = async () => {
    setLoadingApiKeys(true);
    try {
      const keys = await apiService.getApiKeys();
      setApiKeys(keys);
    } catch (error) {
      showNotification('error', error.message || 'Failed to load API keys');
    } finally {
      setLoadingApiKeys(false);
    }
  };

  useEffect(() => {
    if (activeTab === 'api-keys') {
      loadApiKeys();
    }
  }, [activeTab]);

  const handleCreateApiKey = async (e) => {
    e.preventDefault();
    try {
      const response = await apiService.createApiKey(newApiKey.role, newApiKey.name || null);
      setCreatedApiKey(response);
      setShowCreateForm(false);
      setNewApiKey({ role: 'robot', name: '' });
      showNotification('success', 'API key created successfully. Please save it now - it will only be shown once!');
      loadApiKeys();
    } catch (error) {
      showNotification('error', error.message || 'Failed to create API key');
    }
  };

  const handleRevokeApiKey = async (apiKey) => {
    // Use name if available, otherwise use the full key
    const identifier = apiKey.name || apiKey.key;
    const displayName = apiKey.name || 'this API key';
    
    if (!window.confirm(`Are you sure you want to revoke ${displayName}? This action cannot be undone.`)) {
      return;
    }
    
    try {
      await apiService.revokeApiKey(identifier);
      showNotification('success', 'API key revoked successfully');
      loadApiKeys();
    } catch (error) {
      showNotification('error', error.message || 'Failed to revoke API key');
    }
  };

  const copyApiKeyToClipboard = async (key) => {
    try {
      await navigator.clipboard.writeText(key);
      showNotification('success', 'API key copied to clipboard');
    } catch (err) {
      showNotification('error', 'Failed to copy API key');
    }
  };

  const maskApiKey = (key) => {
    if (!key) return 'N/A';
    if (key.length <= 20) return key;
    return key.substring(0, 10) + '...' + key.substring(key.length - 10);
  };

  if (!user) {
    return (
      <div className="min-h-screen bg-gray-50 flex items-center justify-center">
        <LoadingSpinner />
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8">
        {/* Header */}
        <div className="bg-white shadow rounded-lg mb-8">
          <div className="px-4 py-5 sm:p-6">
            <div className="flex items-center">
              <div className="flex-shrink-0">
                <div className="h-16 w-16 bg-gradient-to-r from-blue-500 to-purple-600 rounded-full flex items-center justify-center">
                  <span className="text-xl font-bold text-white">
                    {(user.full_name || user.name || user.email || user.sub || 'U').charAt(0).toUpperCase()}
                  </span>
                </div>
              </div>
              <div className="ml-4">
                <h1 className="text-2xl font-bold text-gray-900">
                  {user.full_name || user.name || user.email || user.sub || 'User Profile'}
                </h1>
                <p className="text-sm text-gray-500">
                  {user.email || user.sub || 'No contact information available'}
                </p>
                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium mt-2 ${getRoleBadgeColor(getUserRole(user))}`}>
                  {getUserRole(user)}
                </span>
              </div>
            </div>
          </div>
        </div>

        {/* Tabs */}
        <div className="bg-white shadow rounded-lg">
          <div className="border-b border-gray-200">
            <nav className="-mb-px flex">
              <button
                onClick={() => setActiveTab('profile')}
                className={`py-4 px-6 border-b-2 font-medium text-sm ${
                  activeTab === 'profile'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Profile Information
              </button>
              <button
                onClick={() => setActiveTab('api-keys')}
                className={`py-4 px-6 border-b-2 font-medium text-sm ${
                  activeTab === 'api-keys'
                    ? 'border-blue-500 text-blue-600'
                    : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
                }`}
              >
                Application API Key
              </button>
              {/* Security tab removed since password changes are handled in IdM */}
            </nav>
          </div>

          <div className="px-4 py-5 sm:p-6">
            {activeTab === 'profile' && (
              <div className="space-y-6">
                <h3 className="text-lg leading-6 font-medium text-gray-900">
                  Profile Information
                </h3>
                
                <div className="grid grid-cols-1 gap-6 sm:grid-cols-2">
                  <div>
                    <label className="block text-sm font-medium text-gray-700">
                      User ID
                    </label>
                    <div className="mt-1 text-sm text-gray-900 bg-gray-50 px-3 py-2 rounded-md font-mono">
                      {user.sub || 'N/A'}
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700">
                      Email Address
                    </label>
                    <div className="mt-1 text-sm text-gray-900 bg-gray-50 px-3 py-2 rounded-md">
                      {user.email || 'N/A'}
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700">
                      Full Name
                    </label>
                    <div className="mt-1 text-sm text-gray-900 bg-gray-50 px-3 py-2 rounded-md">
                      {user.full_name || user.name || 'N/A'}
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-gray-700">
                      Role
                    </label>
                    <div className="mt-1">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleBadgeColor(getUserRole(user))}`}>
                        {getUserRole(user)}
                      </span>
                    </div>
                  </div>

                  {user.groups && user.groups.length > 0 && (
                    <div className="sm:col-span-2">
                      <label className="block text-sm font-medium text-gray-700">
                        Groups
                      </label>
                      <div className="mt-1 flex flex-wrap gap-2">
                        {user.groups.map((group, index) => (
                          <span key={index} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800">
                            {group}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                <div className="pt-4 border-t border-gray-200">
                  <p className="text-sm text-gray-500">
                    Profile information is managed by the system administrator. 
                    If you need to update your details, please contact support.
                  </p>
                </div>

                {/* JWT Information Section */}
                <div className="pt-6 border-t border-gray-200">
                  <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4">
                    JWT Token Information
                  </h3>
                  
                  <div className="bg-gray-50 rounded-lg p-4">
                    <div className="flex items-center justify-between mb-3">
                      <label className="block text-sm font-medium text-gray-700">
                        Access Token
                      </label>
                      <div className="flex space-x-2">
                        <button
                          onClick={() => setShowJWT(!showJWT)}
                          className="inline-flex items-center px-3 py-1.5 border border-gray-300 shadow-sm text-xs font-medium rounded text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        >
                          {showJWT ? 'Hide' : 'Show'} Token
                        </button>
                        <button
                          onClick={copyJWTToClipboard}
                          className="inline-flex items-center px-3 py-1.5 border border-gray-300 shadow-sm text-xs font-medium rounded text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        >
                          Copy
                        </button>
                      </div>
                    </div>
                    
                    <div className="bg-white border border-gray-200 rounded-md p-3">
                      <code className="text-sm text-gray-900 break-all font-mono">
                        {showJWT ? getJWTToken() || 'No token available' : maskJWT(getJWTToken())}
                      </code>
                    </div>
                    
                    <div className="mt-3 text-xs text-gray-500">
                      <p>• Token is used for API authentication</p>
                      <p>• Keep your token secure and don't share it</p>
                      <p>• Token expires in 24 hours and requires re-authentication</p>
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'api-keys' && (
              <div className="space-y-6">
                <div className="flex items-center justify-between">
                  <h3 className="text-lg leading-6 font-medium text-gray-900">
                    Application API Keys
                  </h3>
                  <button
                    onClick={() => {
                      setShowCreateForm(true);
                      setCreatedApiKey(null);
                    }}
                    className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                  >
                    Create API Key
                  </button>
                </div>

                <p className="text-sm text-gray-500">
                  API keys allow applications to authenticate with the API. Each key has a specific role that determines its permissions.
                </p>

                {/* New API Key Display */}
                {createdApiKey && (
                  <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
                    <div className="flex items-start">
                      <div className="flex-shrink-0">
                        <svg className="h-5 w-5 text-yellow-400" viewBox="0 0 20 20" fill="currentColor">
                          <path fillRule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
                        </svg>
                      </div>
                      <div className="ml-3 flex-1">
                        <h4 className="text-sm font-medium text-yellow-800">
                          {createdApiKey.warning || 'Important: Save this API key now!'}
                        </h4>
                        <div className="mt-2 text-sm text-yellow-700">
                          <p className="mb-2">This key will only be shown once. Please copy and store it securely.</p>
                          <div className="bg-white border border-yellow-300 rounded-md p-3 mb-3">
                            <div className="flex items-center justify-between">
                              <code className="text-sm text-gray-900 break-all font-mono">
                                {createdApiKey.key}
                              </code>
                              <button
                                onClick={() => copyApiKeyToClipboard(createdApiKey.key)}
                                className="ml-2 inline-flex items-center px-2 py-1 border border-gray-300 shadow-sm text-xs font-medium rounded text-gray-700 bg-white hover:bg-gray-50"
                              >
                                Copy
                              </button>
                            </div>
                          </div>
                          <div className="text-xs">
                            <p><strong>Role:</strong> {createdApiKey.role}</p>
                            {createdApiKey.name && <p><strong>Name:</strong> {createdApiKey.name}</p>}
                            <p><strong>Created:</strong> {new Date(createdApiKey.created_at).toLocaleString()}</p>
                          </div>
                        </div>
                        <div className="mt-3">
                          <button
                            onClick={() => setCreatedApiKey(null)}
                            className="text-sm font-medium text-yellow-800 hover:text-yellow-900"
                          >
                            Dismiss
                          </button>
                        </div>
                      </div>
                    </div>
                  </div>
                )}

                {/* Create API Key Form */}
                {showCreateForm && !createdApiKey && (
                  <div className="bg-gray-50 rounded-lg p-4 border border-gray-200">
                    <h4 className="text-md font-medium text-gray-900 mb-4">Create New API Key</h4>
                    <form onSubmit={handleCreateApiKey} className="space-y-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Role <span className="text-red-500">*</span>
                        </label>
                        <select
                          value={newApiKey.role}
                          onChange={(e) => setNewApiKey({ ...newApiKey, role: e.target.value })}
                          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm"
                          required
                        >
                          <option value="robot">Robot</option>
                          <option value="user">User</option>
                          <option value="admin">Admin</option>
                          <option value="moderator">Moderator</option>
                          <option value="guest">Guest</option>
                        </select>
                        <p className="mt-1 text-xs text-gray-500">
                          The role determines what permissions this API key will have.
                        </p>
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Name (Optional)
                        </label>
                        <input
                          type="text"
                          value={newApiKey.name}
                          onChange={(e) => setNewApiKey({ ...newApiKey, name: e.target.value })}
                          placeholder="e.g., Production Service Key"
                          className="mt-1 block w-full rounded-md border-gray-300 shadow-sm focus:border-blue-500 focus:ring-blue-500 sm:text-sm"
                        />
                        <p className="mt-1 text-xs text-gray-500">
                          A descriptive name to help identify this API key.
                        </p>
                      </div>
                      <div className="flex space-x-3">
                        <button
                          type="submit"
                          className="inline-flex items-center px-4 py-2 border border-transparent shadow-sm text-sm font-medium rounded-md text-white bg-blue-600 hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        >
                          Create API Key
                        </button>
                        <button
                          type="button"
                          onClick={() => {
                            setShowCreateForm(false);
                            setNewApiKey({ role: 'robot', name: '' });
                          }}
                          className="inline-flex items-center px-4 py-2 border border-gray-300 shadow-sm text-sm font-medium rounded-md text-gray-700 bg-white hover:bg-gray-50 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-blue-500"
                        >
                          Cancel
                        </button>
                      </div>
                    </form>
                  </div>
                )}

                {/* API Keys List */}
                <div>
                  <h4 className="text-md font-medium text-gray-900 mb-4">Your API Keys</h4>
                  {loadingApiKeys ? (
                    <div className="flex justify-center py-8">
                      <LoadingSpinner />
                    </div>
                  ) : apiKeys.length === 0 ? (
                    <div className="text-center py-8 text-gray-500">
                      <p>No API keys found. Create your first API key to get started.</p>
                    </div>
                  ) : (
                    <div className="space-y-3">
                      {apiKeys.map((key) => (
                        <div key={key.key} className="bg-gray-50 rounded-lg p-4 border border-gray-200">
                          <div className="flex items-start justify-between">
                            <div className="flex-1">
                              <div className="flex items-center space-x-2 mb-2">
                                <code className="text-sm text-gray-900 font-mono bg-white px-2 py-1 rounded border">
                                  {maskApiKey(key.key)}
                                </code>
                                <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${getRoleBadgeColor(key.role)}`}>
                                  {key.role}
                                </span>
                              </div>
                              <div className="text-xs text-gray-500 space-y-1">
                                {key.name && <p><strong>Name:</strong> {key.name}</p>}
                                <p><strong>Created:</strong> {new Date(key.created_at).toLocaleString()}</p>
                                <p><strong>Created by:</strong> {key.created_by || 'N/A'}</p>
                              </div>
                            </div>
                            <div className="flex space-x-2 ml-4">
                              <button
                                onClick={() => handleRevokeApiKey(key)}
                                className="inline-flex items-center px-3 py-1.5 border border-red-300 shadow-sm text-xs font-medium rounded text-red-700 bg-white hover:bg-red-50"
                              >
                                Revoke
                              </button>
                            </div>
                          </div>
                        </div>
                      ))}
                    </div>
                  )}
                </div>

                <div className="pt-4 border-t border-gray-200">
                  <p className="text-sm text-gray-500">
                    <strong>Security Tips:</strong>
                  </p>
                  <ul className="mt-2 text-sm text-gray-500 list-disc list-inside space-y-1">
                    <li>Keep your API keys secure and never share them publicly</li>
                    <li>Use different keys for different applications or environments</li>
                    <li>Revoke keys that are no longer needed or have been compromised</li>
                    <li>API keys are shown in full only when first created</li>
                  </ul>
                </div>
              </div>
            )}

            {/* Security section removed */}
          </div>
        </div>
      </div>

      {/* Notification */}
      {notification.show && (
        <Notification
          type={notification.type}
          message={notification.message}
          onClose={() => setNotification({ show: false, type: '', message: '' })}
        />
      )}
    </div>
  );
};

export default Profile;
