export function createNodeData(def) {
  return {
    label: def.label,
    type: def.type,
    category: def.category,
    icon: def.icon,
    config: { ...def.defaultConfig },
    inputs: [...def.inputs],
    outputs: [...def.outputs],
  };
}

export function buildLuaOutputs(outputCodes) {
  return outputCodes.map((code) => ({
    id: `out-${code}`,
    name: `int = ${code}`,
    type: 'any',
  }));
}

/**
 * Build outputs for a Predefined node from an action definition.
 * actionDef.outputs is an array of { id, name } from pw_machine_action.
 * Falls back to a single "Return 0" output.
 */
export function buildPredefinedOutputs(actionDef) {
  if (actionDef?.outputs && Array.isArray(actionDef.outputs) && actionDef.outputs.length > 0) {
    return actionDef.outputs.map((o) => ({
      id: o.id || `out-${o.name}`,
      name: o.name,
      type: 'any',
    }));
  }
  return [{ id: 'out-0', name: 'Return 0', type: 'any' }];
}

/**
 * Build default params for a Predefined node from an action definition.
 * actionDef.params is an array of { name, type, defaultValue? } from pw_machine_action.
 */
export function buildPredefinedParams(actionDef) {
  if (actionDef?.params && Array.isArray(actionDef.params)) {
    return actionDef.params.map((p) => ({
      type: p.type || 'string',
      value: p.defaultValue || '',
      name: p.name || '',
      defaultValue: p.defaultValue || '',
    }));
  }
  return [];
}
